"""
Parameterized generator for GH966_pymc_7890.

Source PR:    https://github.com/pymc-devs/pymc/pull/7890
Source Issue: https://github.com/pymc-devs/pymc/issues/7889

Seed varies: renames 'a_ancestor1' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH966_pymc_7890'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH966_pymc_7890'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('a_ancestor1', 'a_ancestor1' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH966_pymc_7890',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pymc-devs/pymc',
                "pr_number": 7890,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pymc-devs/pymc/pull/7890",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'pymc/sampling/forward.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\n\n"""Functions for prior and posterior predictive sampling."""\n\nimport logging\nimport warnings\n\nfrom collections.abc import Callable, Iterable, Sequence\nfrom typing import (\n    Any,\n    Literal,\n    TypeAlias,\n    cast,\n    overload,\n)\n\nimport numpy as np\nimport xarray\nimport xarray as xr\n\nfrom arviz import InferenceData\nfrom pytensor import tensor as pt\nfrom pytensor.graph import vectorize_graph\nfrom pytensor.graph.basic import (\n    Apply,\n    Constant,\n    Variable,\n)\nfrom pytensor.graph.fg import FunctionGraph\nfrom pytensor.graph.traversal import ancestors, general_toposort, walk\nfrom pytensor.tensor.random.var import RandomGeneratorSharedVariable\nfrom pytensor.tensor.sharedvar import SharedVariable, TensorSharedVariable\nfrom pytensor.tensor.variable import TensorConstant\nfrom rich.console import Console\nfrom rich.progress import BarColumn, TextColumn, TimeElapsedColumn, TimeRemainingColumn\nfrom rich.theme import Theme\n\nimport pymc as pm\n\nfrom pymc.backends.arviz import _DefaultTrace, dataset_to_point_list\nfrom pymc.backends.base import MultiTrace\nfrom pymc.blocking import PointType\nfrom pymc.distributions.shape_utils import change_dist_size\nfrom pymc.model import Model, modelcontext\nfrom pymc.progress_bar import CustomProgress, default_progress_theme\nfrom pymc.pytensorf import compile, rvs_in_graph\nfrom pymc.util import (\n    RandomState,\n    _get_seeds_per_chain,\n    get_default_varnames,\n    point_wrapper,\n)\n\n__all__ = (\n    "compile_forward_sampling_function",\n    "draw",\n    "sample_posterior_predictive",\n    "sample_prior_predictive",\n    "vectorize_over_posterior",\n)\n\nArrayLike: TypeAlias = np.ndarray | list[float]\nPointList: TypeAlias = list[PointType]\n\n_log = logging.getLogger(__name__)\n\n\ndef get_constant_coords(trace_coords: dict[str, np.ndarray], model: Model) -> set:\n    """Get the set of coords that have remained constant between the trace and model."""\n    constant_coords = set()\n    for dim, coord in trace_coords.items():\n        current_coord = model.coords.get(dim, None)\n        current_length = model.dim_lengths.get(dim, None)\n        if isinstance(current_length, TensorSharedVariable):\n            current_length = current_length.get_value()\n        elif isinstance(current_length, TensorConstant):\n            current_length = current_length.data\n        if (\n            current_coord is not None\n            and len(coord) == len(current_coord)\n            and np.all(coord == current_coord)\n        ) or (\n            # Coord was defined without values (only length)\n            current_coord is None and len(coord) == current_length\n        ):\n            constant_coords.add(dim)\n    return constant_coords\n\n\ndef get_vars_in_point_list(trace, model):\n    """Get the list of Variable instances in the model that have values stored in the trace."""\n    if not isinstance(trace, MultiTrace):\n        names_in_trace = list(trace[0])\n    else:\n        names_in_trace = trace.varnames\n    traceable_varnames = {var.name for var in (model.free_RVs + model.deterministics)}\n    vars_in_trace = [model[v] for v in names_in_trace if v in traceable_varnames]\n    return vars_in_trace\n\n\ndef compile_forward_sampling_function(\n    outputs: list[Variable],\n    vars_in_trace: list[Variable],\n    basic_rvs: list[Variable] | None = None,\n    givens_dict: dict[Variable, Any] | None = None,\n    constant_data: dict[str, np.ndarray] | None = None,\n    constant_coords: set[str] | None = None,\n    **kwargs,\n) -> tuple[Callable[..., np.ndarray | list[np.ndarray]], set[Variable]]:\n    """Compile a function to draw samples, conditioned on the values of some variables.\n\n    The goal of this function is to walk the pytensor computational graph from the list\n    of output nodes down to the root nodes, and then compile a function that will produce\n    values for these output nodes. The compiled function will take as inputs the subset of\n    variables in the ``vars_in_trace`` that are deemed to not be **volatile**.\n\n    Volatile variables are variables whose values could change between runs of the\n    compiled function or after inference has been run. These variables are:\n\n    - Variables in the outputs list\n    - ``SharedVariable`` instances that are not ``RandomGeneratorSharedVariable``, and whose values changed with respect to what they were at inference time\n    - Variables that are in the `basic_rvs` list but not in the ``vars_in_trace`` list\n    - Variables that are keys in the ``givens_dict``\n    - Variables that have volatile inputs\n\n    Concretely, this function can be used to compile a function to sample from the\n    posterior predictive distribution of a model that has variables that are conditioned\n    on ``Data`` instances. The variables that depend on the mutable data that have changed\n    will be considered volatile, and as such, they wont be included as inputs into the compiled\n    function. This means that if they have values stored in the posterior, these values will be\n    ignored and new values will be computed (in the case of deterministics and potentials) or\n    sampled (in the case of random variables).\n\n    This function also enables a way to impute values for any variable in the computational\n    graph that produces the desired outputs: the ``givens_dict``. This dictionary can be used\n    to set the ``givens`` argument of the pytensor function compilation. This will essentially\n    replace a node in the computational graph with any other expression that has the same\n    type as the desired node. Passing variables in the givens_dict is considered an intervention\n    that might lead to different variable values from those that could have been seen during\n    inference, as such, **any variable that is passed in the ``givens_dict`` will be considered\n    volatile**.\n\n    Parameters\n    ----------\n    outputs : List[pytensor.graph.basic.Variable]\n        The list of variables that will be returned by the compiled function\n    vars_in_trace : List[pytensor.graph.basic.Variable]\n        The list of variables that are assumed to have values stored in the trace\n    basic_rvs : Optional[List[pytensor.graph.basic.Variable]]\n        A list of random variables that are defined in the model. This list (which could be the\n        output of ``model.basic_RVs``) should have a reference to the variables that should\n        be considered as random variable instances. This includes variables that have\n        a ``RandomVariable`` owner op, but also unpure random variables like Mixtures, or\n        Censored distributions.\n    givens_dict : Optional[Dict[pytensor.graph.basic.Variable, Any]]\n        A dictionary that maps tensor variables to the values that should be used to replace them\n        in the compiled function. The types of the key and value should match or an error will be\n        raised during compilation.\n    constant_data : Optional[Dict[str, numpy.ndarray]]\n        A dictionary that maps the names of ``Data`` instances to their\n        corresponding values at inference time. If a model was created with ``Data``, these\n        are stored as ``SharedVariable`` with the name of the data variable and a value equal to\n        the initial data. At inference time, this information is stored in ``InferenceData``\n        objects under the ``constant_data`` group, which allows us to check whether a\n        ``SharedVariable`` instance changed its values after inference or not. If the values have\n        changed, then the ``SharedVariable`` is assumed to be volatile. If it has not changed, then\n        the ``SharedVariable`` is assumed to not be volatile. If a ``SharedVariable`` is not found\n        in either ``constant_data`` or ``constant_coords``, then it is assumed to be volatile.\n        Setting ``constant_data`` to ``None`` is equivalent to passing an empty dictionary.\n    constant_coords : Optional[Set[str]]\n        A set with the names of the mutable coordinates that have not changed their shape after\n        inference. If a model was created with mutable coordinates, these are stored as\n        ``SharedVariable`` with the name of the coordinate and a value equal to the length of said\n        coordinate. This set let\'s us check if a ``SharedVariable`` is a mutated coordinate, in\n        which case, it is considered volatile. If a ``SharedVariable`` is not found\n        in either ``constant_data`` or ``constant_coords``, then it is assumed to be volatile.\n        Setting ``constant_coords`` to ``None`` is equivalent to passing an empty set.\n\n    Returns\n    -------\n    function: Callable\n        Compiled forward sampling PyTensor function\n    volatile_basic_rvs: Set of Variable\n        Set of all basic_rvs that were considered volatile and will be resampled when\n        the function is evaluated\n    """\n    if givens_dict is None:\n        givens_dict = {}\n\n    if basic_rvs is None:\n        basic_rvs = []\n\n    if constant_data is None:\n        constant_data = {}\n    if constant_coords is None:\n        constant_coords = set()\n\n    # We define a helper function to check if shared values match to an array\n    def shared_value_matches(var):\n        try:\n            old_array_value = constant_data[var.name]\n        except KeyError:\n            return var.name in constant_coords\n        current_shared_value = var.get_value(borrow=True)\n        return np.array_equal(old_array_value, current_shared_value)\n\n    # We need a function graph to walk the clients and propagate the volatile property\n    fg = FunctionGraph(outputs=outputs, clone=False)\n\n    # Walk the graph from inputs to outputs and tag the volatile variables\n    nodes: list[Variable] = general_toposort(\n        fg.outputs, deps=lambda x: x.owner.inputs if x.owner else []\n    )  # type: ignore[call-overload]\n    volatile_nodes: set[Any] = set()\n    for node in nodes:\n        if (\n            node in fg.outputs\n            or node in givens_dict\n            or (  # SharedVariables, except RandomState/Generators\n                isinstance(node, SharedVariable)\n                and not isinstance(node, RandomGeneratorSharedVariable)\n                and not shared_value_matches(node)\n            )\n            or (  # Basic RVs that are not in the trace\n                node in basic_rvs and node not in vars_in_trace\n            )\n            or (  # Variables that have any volatile input\n                node.owner and any(inp in volatile_nodes for inp in node.owner.inputs)\n            )\n        ):\n            volatile_nodes.add(node)\n\n    # Collect the function inputs by walking the graph from the outputs. Inputs will be:\n    # 1. Random variables that are not volatile\n    # 2. Variables that have no owner and are not constant or shared\n    inputs = []\n\n    def expand(node):\n        if (\n            (\n                node.owner is None and not isinstance(node, Constant | SharedVariable)\n            )  # Variables without owners that are not constant or shared\n            or node in vars_in_trace  # Variables in the trace\n        ) and node not in volatile_nodes:\n            # This test will include variables without owners, and that are not constant\n            # or shared, because these nodes will never be considered volatile\n            inputs.append(node)\n        if node.owner:\n            return node.owner.inputs\n\n    # walk produces a generator, so we have to actually exhaust the generator in a list to walk\n    # the entire graph\n    list(walk(fg.outputs, expand))\n\n    # Populate the givens list\n    givens = [\n        (\n            node,\n            value\n            if isinstance(value, Variable | Apply)\n            else pt.constant(value, dtype=getattr(node, "dtype", None), name=node.name),\n        )\n        for node, value in givens_dict.items()\n    ]\n\n    return (\n        compile(inputs, fg.outputs, givens=givens, on_unused_input="ignore", **kwargs),\n        set(basic_rvs) & (volatile_nodes - set(givens_dict)),  # Basic RVs that will be resampled\n    )\n\n\ndef draw(\n    vars: Variable | Sequence[Variable],\n    draws: int = 1,\n    random_seed: RandomState = None,\n    **kwargs,\n) -> np.ndarray | list[np.ndarray]:\n    """Draw samples for one variable or a list of variables.\n\n    Parameters\n    ----------\n    vars : TensorVariable or iterable of TensorVariable\n        A variable or a list of variables for which to draw samples.\n    draws : int, default 1\n        Number of samples needed to draw.\n    random_seed : int, RandomState or numpy_Generator, optional\n        Seed for the random number generator.\n    **kwargs : dict, optional\n        Keyword arguments for :func:`pymc.pytensorf.compile_pymc`.\n\n    Returns\n    -------\n    list of ndarray\n        A list of numpy arrays.\n\n    Examples\n    --------\n        .. code-block:: python\n\n            import pymc as pm\n\n            # Draw samples for one variable\n            with pm.Model():\n                x = pm.Normal("x")\n            x_draws = pm.draw(x, draws=100)\n            print(x_draws.shape)\n\n            # Draw 1000 samples for several variables\n            with pm.Model():\n                x = pm.Normal("x")\n                y = pm.Normal("y", shape=10)\n                z = pm.Uniform("z", shape=5)\n            num_draws = 1000\n            # Draw samples of a list variables\n            draws = pm.draw([x, y, z], draws=num_draws)\n            assert draws[0].shape == (num_draws,)\n            assert draws[1].shape == (num_draws, 10)\n            assert draws[2].shape == (num_draws, 5)\n    """\n    if random_seed is not None:\n        (random_seed,) = _get_seeds_per_chain(random_seed, 1)\n\n    draw_fn = compile(inputs=[], outputs=vars, random_seed=random_seed, **kwargs)\n\n    if draws == 1:\n        return draw_fn()\n\n    # Single variable output\n    if not isinstance(vars, list | tuple):\n        cast(Callable[[], np.ndarray], draw_fn)\n        return np.stack([draw_fn() for _ in range(draws)])\n\n    # Multiple variable output\n    cast(Callable[[], list[np.ndarray]], draw_fn)\n    drawn_values = zip(*(draw_fn() for _ in range(draws)))\n    return [np.stack(v) for v in drawn_values]\n\n\ndef observed_dependent_deterministics(model: Model, extra_observeds=None):\n    """Find deterministics that depend directly on observed variables."""\n    if extra_observeds is None:\n        extra_observeds = []\n\n    deterministics = model.deterministics\n    observed_rvs = set(model.observed_RVs + extra_observeds)\n    blockers = model.basic_RVs\n    return [\n        deterministic\n        for deterministic in deterministics\n        if observed_rvs & set(ancestors([deterministic], blockers=blockers))\n    ]\n\n\n@overload\ndef sample_prior_predictive(\n    draws: int = 500,\n    model: Model | None = None,\n    var_names: Iterable[str] | None = None,\n    random_seed: RandomState = None,\n    return_inferencedata: Literal[True] = True,\n    idata_kwargs: dict | None = None,\n    compile_kwargs: dict | None = None,\n    samples: int | None = None,\n) -> InferenceData: ...\n@overload\ndef sample_prior_predictive(\n    draws: int = 500,\n    model: Model | None = None,\n    var_names: Iterable[str] | None = None,\n    random_seed: RandomState = None,\n    return_inferencedata: Literal[False] = False,\n    idata_kwargs: dict | None = None,\n    compile_kwargs: dict | None = None,\n    samples: int | None = None,\n) -> dict[str, np.ndarray]: ...\ndef sample_prior_predictive(\n    draws: int = 500,\n    model: Model | None = None,\n    var_names: Iterable[str] | None = None,\n    random_seed: RandomState = None,\n    return_inferencedata: bool = True,\n    idata_kwargs: dict | None = None,\n    compile_kwargs: dict | None = None,\n    samples: int | None = None,\n) -> InferenceData | dict[str, np.ndarray]:\n    """Generate samples from the prior predictive distribution.\n\n    Parameters\n    ----------\n    draws : int\n        Number of samples from the prior predictive to generate. Defaults to 500.\n    model : Model (optional if in ``with`` context)\n    var_names : Iterable[str]\n        A list of names of variables for which to compute the prior predictive\n        samples. Defaults to both observed and unobserved RVs. Transformed values\n        are not allowed.\n    random_seed : int, RandomState or Generator, optional\n        Seed for the random number generator.\n    return_inferencedata : bool\n        Whether to return an :class:`arviz:arviz.InferenceData` (True) object or a dictionary (False).\n        Defaults to True.\n    idata_kwargs : dict, optional\n        Keyword arguments for :func:`pymc.to_inference_data`\n    compile_kwargs: dict, optional\n        Keyword arguments for :func:`pymc.pytensorf.compile_pymc`.\n    samples : int\n        Number of samples from the prior predictive to generate. Deprecated in favor of `draws`.\n\n    Returns\n    -------\n    arviz.InferenceData or Dict\n        An ArviZ ``InferenceData`` object containing the prior and prior predictive samples (default),\n        or a dictionary with variable names as keys and samples as numpy arrays.\n    """\n    if samples is not None:\n        warnings.warn(\n            f"The samples argument has been deprecated in favor of draws. Use draws={samples} going forward.",\n            DeprecationWarning,\n            stacklevel=1,\n        )\n\n        draws = samples\n\n    model = modelcontext(model)\n\n    if model.potentials:\n        warnings.warn(\n            "The effect of Potentials on other parameters is ignored during prior predictive sampling. "\n            "This is likely to lead to invalid or biased predictive samples.",\n            UserWarning,\n            stacklevel=2,\n        )\n\n    if var_names is None:\n        vars_: set[str] = {var.name for var in model.basic_RVs + model.deterministics}\n    else:\n        vars_ = set(var_names)\n\n    names = sorted(get_default_varnames(vars_, include_transformed=False))\n    vars_to_sample = [model[name] for name in names]\n\n    # Any variables from var_names still missing are assumed to be transformed variables.\n    missing_names = vars_.difference(names)\n    if missing_names:\n        raise ValueError(f"Unrecognized var_names: {missing_names}")\n\n    if random_seed is not None:\n        (random_seed,) = _get_seeds_per_chain(random_seed, 1)\n\n    if compile_kwargs is None:\n        compile_kwargs = {}\n    compile_kwargs.setdefault("allow_input_downcast", True)\n    compile_kwargs.setdefault("accept_inplace", True)\n\n    sampler_fn, volatile_basic_rvs = compile_forward_sampling_function(\n        vars_to_sample,\n        vars_in_trace=[],\n        basic_rvs=model.basic_RVs,\n        givens_dict=None,\n        random_seed=random_seed,\n        **compile_kwargs,\n    )\n\n    # All model variables have a name, but mypy does not know this\n    _log.info(f"Sampling: {sorted(volatile_basic_rvs, key=lambda var: var.name)}")  # type: ignore[arg-type, return-value]\n    values = zip(*(sampler_fn() for i in range(draws)))\n\n    data = {k: np.stack(v) for k, v in zip(names, values)}\n    if data is None:\n        raise AssertionError(f"No variables sampled: attempting to sample {names}")\n\n    prior: dict[str, np.ndarray] = {}\n    for var_name in vars_:\n        if var_name in data:\n            prior[var_name] = data[var_name]\n\n    if not return_inferencedata:\n        return prior\n    ikwargs: dict[str, Any] = {"model": model}\n    if idata_kwargs:\n        ikwargs.update(idata_kwargs)\n    return pm.to_inference_data(prior=prior, **ikwargs)\n\n\n@overload\ndef sample_posterior_predictive(\n    trace,\n    model: Model | None = None,\n    var_names: list[str] | None = None,\n    sample_dims: list[str] | None = None,\n    random_seed: RandomState = None,\n    progressbar: bool = True,\n    progressbar_theme: Theme | None = default_progress_theme,\n    return_inferencedata: Literal[True] = True,\n    extend_inferencedata: bool = False,\n    predictions: bool = False,\n    idata_kwargs: dict | None = None,\n    compile_kwargs: dict | None = None,\n) -> InferenceData: ...\n@overload\ndef sample_posterior_predictive(\n    trace,\n    model: Model | None = None,\n    var_names: list[str] | None = None,\n    sample_dims: list[str] | None = None,\n    random_seed: RandomState = None,\n    progressbar: bool = True,\n    progressbar_theme: Theme | None = default_progress_theme,\n    return_inferencedata: Literal[False] = False,\n    extend_inferencedata: bool = False,\n    predictions: bool = False,\n    idata_kwargs: dict | None = None,\n    compile_kwargs: dict | None = None,\n) -> dict[str, np.ndarray]: ...\ndef sample_posterior_predictive(\n    trace,\n    model: Model | None = None,\n    var_names: list[str] | None = None,\n    sample_dims: list[str] | None = None,\n    random_seed: RandomState = None,\n    progressbar: bool = True,\n    progressbar_theme: Theme | None = default_progress_theme,\n    return_inferencedata: bool = True,\n    extend_inferencedata: bool = False,\n    predictions: bool = False,\n    idata_kwargs: dict | None = None,\n    compile_kwargs: dict | None = None,\n) -> InferenceData | dict[str, np.ndarray]:\n    """Generate forward samples for `var_names`, conditioned on the posterior samples of variables found in the `trace`.\n\n    This method can be used to perform different kinds of model predictions, including posterior predictive checks.\n\n    The matching of unobserved model variables, and posterior samples in the `trace` is made based on the variable\n    names. Therefore, a different model than the one used for posterior sampling may be used for posterior predictive\n    sampling, as long as the variables whose posterior we want to condition on have the same name, and compatible shape\n    and coordinates.\n\n\n    Parameters\n    ----------\n    trace : backend, list, xarray.Dataset, arviz.InferenceData, or MultiTrace\n        Trace generated from MCMC sampling, or a list of dicts (eg. points or from :func:`~pymc.find_MAP`),\n        or :class:`xarray.Dataset` (eg. InferenceData.posterior or InferenceData.prior)\n    model : Model (optional if in ``with`` context)\n        Model to be used to generate the posterior predictive samples. It will\n        generally be the model used to generate the `trace`, but it doesn\'t need to be.\n    var_names : Iterable[str], optional\n        Names of variables for which to compute the posterior predictive samples.\n        By default, only observed variables are sampled.\n        See the example below for what happens when this argument is customized.\n    sample_dims : list of str, optional\n        Dimensions over which to loop and generate posterior predictive samples.\n        When ``sample_dims`` is ``None`` (default) both "chain" and "draw" are considered sample\n        dimensions. Only taken into account when `trace` is InferenceData or Dataset.\n    random_seed : int, RandomState or Generator, optional\n        Seed for the random number generator.\n    progressbar : bool\n        Whether to display a progress bar in the command line. The bar shows the percentage\n        of completion, the sampling speed in samples per second (SPS), and the estimated remaining\n        time until completion ("expected time of arrival"; ETA).\n    return_inferencedata : bool, default True\n        Whether to return an :class:`arviz:arviz.InferenceData` (True) object or a dictionary (False).\n    extend_inferencedata : bool, default False\n        Whether to automatically use :meth:`arviz.InferenceData.extend` to add the posterior predictive samples to\n        `trace` or not. If True, `trace` is modified inplace but still returned.\n    predictions : bool, default False\n        Flag used to set the location of posterior predictive samples within the returned ``arviz.InferenceData`` object.\n        If False, assumes samples are generated based on the fitting data to be used for posterior predictive checks,\n        and samples are stored in the ``posterior_predictive``. If True, assumes samples are generated based on\n        out-of-sample data as predictions, and samples are stored in the ``predictions`` group.\n    idata_kwargs : dict, optional\n        Keyword arguments for :func:`pymc.to_inference_data` if ``predictions=False`` or to\n        :func:`pymc.predictions_to_inference_data` otherwise.\n    compile_kwargs: dict, optional\n        Keyword arguments for :func:`pymc.pytensorf.compile_pymc`.\n\n    Returns\n    -------\n    arviz.InferenceData or Dict\n        An ArviZ ``InferenceData`` object containing the posterior predictive samples (default), or\n        a dictionary with variable names as keys, and samples as numpy arrays.\n\n\n    Examples\n    --------\n    Posterior predictive checks and predictions\n    ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n    The most common use of `sample_posterior_predictive` is to perform posterior predictive checks (in-sample predictions)\n    and new model predictions (out-of-sample predictions).\n\n    .. code-block:: python\n\n        import pymc as pm\n\n        with pm.Model(coords={"trial": [0, 1, 2]}) as model:\n            x = pm.Data("x", [-1, 0, 1], dims=["trial"])\n            beta = pm.Normal("beta")\n            noise = pm.HalfNormal("noise")\n            y = pm.Normal("y", mu=x * beta, sigma=noise, observed=[-2, 0, 3], dims=["trial"])\n\n            idata = pm.sample()\n            # in-sample predictions\n            posterior_predictive = pm.sample_posterior_predictive(idata).posterior_predictive\n\n        with model:\n            pm.set_data({"x": [-2, 2]}, coords={"trial": [3, 4]})\n            # out-of-sample predictions\n            predictions = pm.sample_posterior_predictive(idata, predictions=True).predictions\n\n\n    Using different models\n    ^^^^^^^^^^^^^^^^^^^^^^\n\n    It\'s common to use the same model for posterior and posterior predictive sampling, but this is not required.\n    The matching between unobserved model variables and posterior samples is based on the name alone.\n\n    For the last example we could have created a new predictions model. Note that we have to specify\n    `var_names` explicitly, because the newly defined `y` was not given any observations:\n\n    .. code-block:: python\n\n        with pm.Model(coords={"trial": [3, 4]}) as predictions_model:\n            x = pm.Data("x", [-2, 2], dims=["trial"])\n            beta = pm.Normal("beta")\n            noise = pm.HalfNormal("noise")\n            y = pm.Normal("y", mu=x * beta, sigma=noise, dims=["trial"])\n\n            predictions = pm.sample_posterior_predictive(\n                idata, var_names=["y"], predictions=True\n            ).predictions\n\n\n    The new model may even have a different structure and unobserved variables that don\'t exist in the trace.\n    These variables will also be forward sampled. In the following example we added a new ``extra_noise``\n    variable between the inferred posterior ``noise`` and the new StudentT observational distribution  ``y``:\n\n    .. code-block:: python\n\n        with pm.Model(coords={"trial": [3, 4]}) as distinct_predictions_model:\n            x = pm.Data("x", [-2, 2], dims=["trial"])\n            beta = pm.Normal("beta")\n            noise = pm.HalfNormal("noise")\n            extra_noise = pm.HalfNormal("extra_noise", sigma=noise)\n            y = pm.StudentT("y", nu=4, mu=x * beta, sigma=extra_noise, dims=["trial"])\n\n            predictions = pm.sample_posterior_predictive(\n                idata, var_names=["y"], predictions=True\n            ).predictions\n\n\n    For more about out-of-model predictions, see this `blog post <https://www.pymc-labs.com/blog-posts/out-of-model-predictions-with-pymc/>`_.\n\n    The behavior of `var_names`\n    ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n    The function returns forward samples for any variable included in `var_names`,\n    conditioned on the values of other random variables found in the trace.\n\n    To ensure the samples are internally consistent, any random variable that depends\n    on another random variable that is being sampled is itself sampled, even if\n    this variable is present in the trace and was not included in `var_names`.\n    The final list of variables being sampled is shown in the log output.\n\n    Note that if a random variable has no dependency on other random variables,\n    these forward samples are equivalent to their prior samples.\n    Likewise, if all random variables are being sampled, the behavior of this function\n    is equivalent to that of :func:`~pymc.sample_prior_predictive`.\n\n    .. warning:: A random variable included in `var_names` will never be copied from the posterior group. It will always be sampled as described above. If you want, you can copy manually via ``idata.posterior_predictive["var_name"] = idata.posterior["var_name"]``.\n\n\n    The following code block explores how the behavior changes with different `var_names`:\n\n    .. code-block:: python\n\n        from logging import getLogger\n        import pymc as pm\n\n        # Some environments like google colab suppress\n        # the default logging output of PyMC\n        getLogger("pymc").setLevel("INFO")\n\n        kwargs = {"progressbar": False, "random_seed": 0}\n\n        with pm.Model() as model:\n            x = pm.Normal("x")\n            y = pm.Normal("y")\n            z = pm.Normal("z", x + y**2)\n            det = pm.Deterministic("det", pm.math.exp(z))\n            obs = pm.Normal("obs", det, 1, observed=[20])\n\n            idata = pm.sample(tune=10, draws=10, chains=2, **kwargs)\n\n    Default behavior. Generate samples of ``obs``, conditioned on the posterior samples of ``z`` found in the trace.\n    These are often referred to as posterior predictive samples in the literature:\n\n    .. code-block:: python\n\n        with model:\n            pm.sample_posterior_predictive(idata, var_names=["obs"], **kwargs)\n            # Sampling: [obs]\n\n    Re-compute the deterministic variable ``det``, conditioned on the posterior samples of ``z`` found in the trace:\n\n    .. code :: python\n\n          pm.sample_posterior_predictive(idata, var_names=["det"], **kwargs)\n          # Sampling: []\n\n    Generate samples of ``z`` and ``det``, conditioned on the posterior samples of ``x`` and ``y`` found in the trace.\n\n    .. code :: python\n\n        with model:\n            pm.sample_posterior_predictive(idata, var_names=["z", "det"], **kwargs)\n            # Sampling: [z]\n\n\n    Generate samples of ``y``, ``z`` and ``det``, conditioned on the posterior samples of ``x`` found in the trace.\n\n    Note: The samples of ``y`` are equivalent to its prior, since it does not depend on any other variables.\n    In contrast, the samples of ``z`` and ``det`` depend on the new samples of ``y`` and the posterior samples of\n    ``x`` found in the trace.\n\n    .. code :: python\n\n        with model:\n            pm.sample_posterior_predictive(idata, var_names=["y", "z", "det"], **kwargs)\n            # Sampling: [y, z]\n\n\n    Same as before, except ``z`` is not stored in the returned trace.\n    For computing ``det`` we still have to sample ``z`` as it depends on ``y``, which is also being sampled.\n\n    .. code :: python\n\n        with model:\n            pm.sample_posterior_predictive(idata, var_names=["y", "det"], **kwargs)\n            # Sampling: [y, z]\n\n    Every random variable is sampled. This is equivalent to calling :func:`~pymc.sample_prior_predictive`\n\n    .. code :: python\n\n        with model:\n            pm.sample_posterior_predictive(idata, var_names=["x", "y", "z", "det", "obs"], **kwargs)\n            # Sampling: [x, y, z, obs]\n\n\n    .. danger:: Including a :func:`~pymc.Deterministic` in `var_names` may incorrectly force a random variable to be resampled, as happens with ``z`` in the following example:\n\n\n    .. code :: python\n\n        with pm.Model() as model:\n          x = pm.Normal("x")\n          y = pm.Normal("y")\n          det_xy = pm.Deterministic("det_xy", x + y**2)\n          z = pm.Normal("z", det_xy)\n          det_z = pm.Deterministic("det_z", pm.math.exp(z))\n          obs = pm.Normal("obs", det_z, 1, observed=[20])\n\n          idata = pm.sample(tune=10, draws=10, chains=2, **kwargs)\n\n          pm.sample_posterior_predictive(idata, var_names=["det_xy", "det_z"], **kwargs)\n          # Sampling: [z]\n\n\n    Controlling the number of samples\n    ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n\n    You can manipulate the InferenceData to control the number of samples\n\n    .. code-block:: python\n\n        import pymc as pm\n\n        with pm.Model() as model:\n            ...\n            idata = pm.sample()\n\n    Generate 1 posterior predictive sample for every 5 posterior samples.\n\n    .. code-block:: python\n\n        thinned_idata = idata.sel(draw=slice(None, None, 5))\n        with model:\n            idata.extend(pm.sample_posterior_predictive(thinned_idata))\n\n\n    Generate 5 posterior predictive samples for every posterior sample.\n\n    .. code-block:: python\n\n        expanded_idata = idata.copy()\n        expanded_idata.posterior = idata.posterior.expand_dims(pred_id=5)\n        with model:\n            pm.sample_posterior_predictive(\n                expanded_idata,\n                sample_dims=["chain", "draw", "pred_id"],\n                extend_inferencedata=True,\n            )\n\n\n    """\n    _trace: MultiTrace | PointList\n    nchain: int\n    if idata_kwargs is None:\n        idata_kwargs = {}\n    else:\n        idata_kwargs = idata_kwargs.copy()\n    if sample_dims is None:\n        sample_dims = ["chain", "draw"]\n    constant_data: dict[str, np.ndarray] = {}\n    trace_coords: dict[str, np.ndarray] = {}\n    if "coords" not in idata_kwargs:\n        idata_kwargs["coords"] = {}\n    idata: InferenceData | None = None\n    observed_data = None\n    stacked_dims = None\n    if isinstance(trace, InferenceData):\n        _constant_data = getattr(trace, "constant_data", None)\n        if _constant_data is not None:\n            trace_coords.update({str(k): v.data for k, v in _constant_data.coords.items()})\n            constant_data.update({str(k): v.data for k, v in _constant_data.items()})\n        idata = trace\n        observed_data = trace.get("observed_data", None)\n        trace = trace["posterior"]\n    if isinstance(trace, xarray.Dataset):\n        trace_coords.update({str(k): v.data for k, v in trace.coords.items()})\n        _trace, stacked_dims = dataset_to_point_list(trace, sample_dims)\n        nchain = 1\n    elif isinstance(trace, MultiTrace):\n        _trace = trace\n        nchain = _trace.nchains\n    elif isinstance(trace, list) and all(isinstance(x, dict) for x in trace):\n        _trace = trace\n        nchain = 1\n    else:\n        raise TypeError(f"Unsupported type for `trace` argument: {type(trace)}.")\n    len_trace = len(_trace)\n\n    if isinstance(_trace, MultiTrace):\n        samples = sum(len(v) for v in _trace._straces.values())\n    elif isinstance(_trace, list):\n        # this is a list of points\n        samples = len(_trace)\n    else:\n        raise TypeError(\n            f"Do not know how to compute number of samples for trace argument of type {type(_trace)}"\n        )\n\n    assert samples is not None\n\n    model = modelcontext(model)\n\n    if model.potentials:\n        warnings.warn(\n            "The effect of Potentials on other parameters is ignored during posterior predictive sampling. "\n            "This is likely to lead to invalid or biased predictive samples.",\n            UserWarning,\n            stacklevel=2,\n        )\n\n    constant_coords = get_constant_coords(trace_coords, model)\n\n    if var_names is not None:\n        vars_ = [model[x] for x in var_names]\n    else:\n        observed_vars = model.observed_RVs\n        if observed_data is not None:\n            observed_vars += [\n                model[x] for x in observed_data if x in model and x not in observed_vars\n            ]\n        vars_ = observed_vars + observed_dependent_deterministics(model, observed_vars)\n\n    vars_to_sample = list(get_default_varnames(vars_, include_transformed=False))\n\n    if not vars_to_sample:\n        if return_inferencedata and not extend_inferencedata:\n            return InferenceData()\n        elif return_inferencedata and extend_inferencedata:\n            return trace if idata is None else idata\n        return {}\n\n    vars_in_trace = get_vars_in_point_list(_trace, model)\n\n    if random_seed is not None:\n        (random_seed,) = _get_seeds_per_chain(random_seed, 1)\n\n    if compile_kwargs is None:\n        compile_kwargs = {}\n    compile_kwargs.setdefault("allow_input_downcast", True)\n    compile_kwargs.setdefault("accept_inplace", True)\n\n    _sampler_fn, volatile_basic_rvs = compile_forward_sampling_function(\n        outputs=vars_to_sample,\n        vars_in_trace=vars_in_trace,\n        basic_rvs=model.basic_RVs,\n        givens_dict=None,\n        random_seed=random_seed,\n        constant_data=constant_data,\n        constant_coords=constant_coords,\n        **compile_kwargs,\n    )\n    sampler_fn = point_wrapper(_sampler_fn)\n    # All model variables have a name, but mypy does not know this\n    _log.info(f"Sampling: {sorted(volatile_basic_rvs, key=lambda var: var.name)}")  # type: ignore[arg-type, return-value]\n    ppc_trace_t = _DefaultTrace(samples)\n\n    progress = CustomProgress(\n        "[progress.description]{task.description}",\n        BarColumn(),\n        "[progress.percentage]{task.percentage:>3.0f}%",\n        TimeRemainingColumn(),\n        TextColumn("/"),\n        TimeElapsedColumn(),\n        console=Console(theme=progressbar_theme),\n        disable=not progressbar,\n    )\n\n    try:\n        with progress:\n            task = progress.add_task("Sampling ...", completed=0, total=samples)\n            for idx in range(samples):\n                if nchain > 1:\n                    # the trace object will either be a MultiTrace (and have _straces)...\n                    if hasattr(_trace, "_straces"):\n                        chain_idx, point_idx = np.divmod(idx, len_trace)\n                        chain_idx = chain_idx % nchain\n                        param = cast(MultiTrace, _trace)._straces[chain_idx].point(point_idx)\n                    # ... or a PointList\n                    else:\n                        param = cast(PointList, _trace)[idx % (len_trace * nchain)]\n                # there\'s only a single chain, but the index might hit it multiple times if\n                # the number of indices is greater than the length of the trace.\n                else:\n                    param = _trace[idx % len_trace]\n\n                values = sampler_fn(**param)\n\n                for k, v in zip(vars_, values):\n                    ppc_trace_t.insert(k.name, v, idx)\n\n                progress.advance(task)\n            progress.update(task, refresh=True, completed=samples)\n\n    except KeyboardInterrupt:\n        pass\n\n    ppc_trace = ppc_trace_t.trace_dict\n\n    for k, ary in ppc_trace.items():\n        if stacked_dims is not None:\n            ppc_trace[k] = ary.reshape(\n                (*[len(coord) for coord in stacked_dims.values()], *ary.shape[1:])\n            )\n        else:\n            ppc_trace[k] = ary.reshape((nchain, len_trace, *ary.shape[1:]))\n\n    if not return_inferencedata:\n        return ppc_trace\n    ikwargs: dict[str, Any] = dict(model=model, **idata_kwargs)\n    ikwargs.setdefault("sample_dims", sample_dims)\n    if stacked_dims is not None:\n        coords = ikwargs.get("coords", {})\n        ikwargs["coords"] = {**stacked_dims, **coords}\n    if predictions:\n        if extend_inferencedata:\n            ikwargs.setdefault("idata_orig", idata)\n            ikwargs.setdefault("inplace", True)\n        return pm.predictions_to_inference_data(ppc_trace, **ikwargs)\n    idata_pp = pm.to_inference_data(posterior_predictive=ppc_trace, **ikwargs)\n\n    if extend_inferencedata and idata is not None:\n        idata.extend(idata_pp)\n        return idata\n    return idata_pp\n\n\ndef vectorize_over_posterior(\n    outputs: list[Variable],\n    posterior: xr.Dataset,\n    input_rvs: list[Variable],\n    allow_rvs_in_graph: bool = True,\n    sample_dims: tuple[str, ...] = ("chain", "draw"),\n) -> list[Variable]:\n    """Vectorize outputs over posterior samples of subset of input rvs.\n\n    This function creates a new graph for the supplied outputs, where the required\n    subset of input rvs are replaced by their posterior samples (chain and draw\n    dimensions are flattened). The other input tensors are kept as is.\n\n    Parameters\n    ----------\n    outputs : list[Variable]\n        The list of variables to vectorize over the posterior samples.\n    posterior : xr.Dataset\n        The posterior samples to use as replacements for the `input_rvs`.\n    input_rvs : list[Variable]\n        The list of random variables to replace with their posterior samples.\n    allow_rvs_in_graph : bool\n        Whether to allow random variables to be present in the graph. If False,\n        an error will be raised if any random variables are found in the graph. If\n        True, the remaining random variables will be resized to match the number of\n        draws from the posterior.\n    sample_dims : tuple[str, ...]\n        The dimensions of the posterior samples to use for vectorizing the `input_rvs`.\n\n\n    Returns\n    -------\n    vectorized_outputs : list[Variable]\n        The vectorized variables\n\n    Raises\n    ------\n    RuntimeError\n        If random variables are found in the graph and `allow_rvs_in_graph` is False\n    """\n    # Identify which free RVs are needed to compute `outputs`\n    needed_rvs: list[Variable] = [\n        rv for rv in ancestors(outputs, blockers=input_rvs) if rv in set(input_rvs)\n    ]\n\n    # Replace needed_rvs with actual posterior samples\n    batch_shape = tuple([len(posterior.coords[dim]) for dim in sample_dims])\n    replace_dict: dict[Variable, Variable] = {}\n    for rv in needed_rvs:\n        posterior_samples = posterior[rv.name].data\n\n        replace_dict[rv] = pt.constant(posterior_samples.astype(rv.dtype), name=rv.name)  # type: ignore[attr-defined]\n\n    # Replace the rvs that remain in the graph with resized versions\n    all_rvs = rvs_in_graph(outputs)\n\n    # Once we give values for the needed_rvs (setting them to their posterior samples),\n    # we need to identify the rvs that only depend on these conditioned values, and\n    # don\'t depend on any other rvs or output nodes.\n    # These variables need to be resized because they won\'t be resized implicitly by\n    # the replacement of the needed_rvs or other random variables in the graph when we\n    # later call vectorize_graph.\n    independent_rvs: list[Variable] = []\n    for rv in [\n        rv\n        for rv in general_toposort(  # type: ignore[call-overload]\n            all_rvs, lambda x: x.owner.inputs if x.owner is not None else None\n        )\n        if rv in all_rvs\n    ]:\n        rv_ancestors = ancestors([rv], blockers=[*needed_rvs, *independent_rvs, *outputs])\n        if (\n            rv not in needed_rvs\n            and not ({*outputs, *independent_rvs} & set(rv_ancestors))\n            and {var for var in rv_ancestors if var in all_rvs} <= {rv, *needed_rvs}\n        ):\n            independent_rvs.append(rv)\n    for rv in independent_rvs:\n        replace_dict[rv] = change_dist_size(rv, new_size=batch_shape, expand=True)\n\n    # Vectorize across samples\n    vectorized_outputs = list(vectorize_graph(outputs, replace=replace_dict))\n    for vectorized_output, output in zip(vectorized_outputs, outputs):\n        vectorized_output.name = output.name\n\n    if not allow_rvs_in_graph:\n        remaining_rvs = rvs_in_graph(vectorized_outputs)\n        if remaining_rvs:\n            raise RuntimeError(\n                f"The following random variables found in the extracted graph: {remaining_rvs}"\n            )\n    return vectorized_outputs\n',
            'tests/sampling/test_forward.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport logging\nimport warnings\n\nimport numpy as np\nimport numpy.random as npr\nimport numpy.testing as npt\nimport pytensor\nimport pytensor.tensor as pt\nimport pytest\nimport xarray as xr\n\nfrom arviz import InferenceData\nfrom arviz import from_dict as az_from_dict\nfrom arviz.tests.helpers import check_multiple_attrs\nfrom pytensor import Mode, shared\nfrom pytensor.compile import SharedVariable\nfrom pytensor.graph import graph_inputs\nfrom pytensor.graph.traversal import get_var_by_name, variable_depends_on\nfrom pytensor.tensor.variable import TensorConstant\nfrom scipy import stats\n\nimport pymc as pm\n\nfrom pymc.backends.base import MultiTrace\nfrom pymc.model.transform.optimization import freeze_dims_and_data\nfrom pymc.pytensorf import compile, rvs_in_graph\nfrom pymc.sampling.forward import (\n    compile_forward_sampling_function,\n    get_constant_coords,\n    get_vars_in_point_list,\n    observed_dependent_deterministics,\n    vectorize_over_posterior,\n)\nfrom pymc.testing import fast_unstable_sampling_mode\n\n\nclass TestDraw:\n    def test_univariate(self):\n        with pm.Model():\n            x = pm.Normal("x")\n\n        x_draws = pm.draw(x)\n        assert x_draws.shape == ()\n\n        (x_draws,) = pm.draw([x])\n        assert x_draws.shape == ()\n\n        x_draws = pm.draw(x, draws=10)\n        assert x_draws.shape == (10,)\n\n        (x_draws,) = pm.draw([x], draws=10)\n        assert x_draws.shape == (10,)\n\n    def test_multivariate(self):\n        with pm.Model():\n            mln = pm.Multinomial("mln", n=5, p=np.array([0.25, 0.25, 0.25, 0.25]))\n\n        mln_draws = pm.draw(mln, draws=1)\n        assert mln_draws.shape == (4,)\n\n        (mln_draws,) = pm.draw([mln], draws=1)\n        assert mln_draws.shape == (4,)\n\n        mln_draws = pm.draw(mln, draws=10)\n        assert mln_draws.shape == (10, 4)\n\n        (mln_draws,) = pm.draw([mln], draws=10)\n        assert mln_draws.shape == (10, 4)\n\n    def test_multiple_variables(self):\n        with pm.Model():\n            x = pm.Normal("x")\n            y = pm.Normal("y", shape=10)\n            z = pm.Uniform("z", shape=5)\n            w = pm.Dirichlet("w", a=[1, 1, 1])\n\n        num_draws = 100\n        draws = pm.draw((x, y, z, w), draws=num_draws)\n        assert draws[0].shape == (num_draws,)\n        assert draws[1].shape == (num_draws, 10)\n        assert draws[2].shape == (num_draws, 5)\n        assert draws[3].shape == (num_draws, 3)\n\n    def test_draw_different_samples(self):\n        with pm.Model():\n            x = pm.Normal("x")\n\n        x_draws_1 = pm.draw(x, 100)\n        x_draws_2 = pm.draw(x, 100)\n        assert not np.all(np.isclose(x_draws_1, x_draws_2))\n\n    def test_draw_pytensor_function_kwargs(self):\n        sharedvar = pytensor.shared(0)\n        x = pm.DiracDelta.dist(0.0)\n        y = x + sharedvar\n        draws = pm.draw(\n            y,\n            draws=5,\n            mode=Mode("py"),\n            updates={sharedvar: sharedvar + 1},\n        )\n        assert np.all(draws == np.arange(5))\n\n\nclass TestCompileForwardSampler:\n    @staticmethod\n    def get_function_roots(function):\n        return [\n            var\n            for var in graph_inputs(function.maker.fgraph.outputs)\n            if var.name not in (None, "NoneConst")\n        ]\n\n    @staticmethod\n    def get_function_inputs(function):\n        return {i for i in function.maker.fgraph.inputs if not isinstance(i, SharedVariable)}\n\n    def test_linear_model(self):\n        with pm.Model() as model:\n            x = pm.Data("x", np.linspace(0, 1, 10))\n            y = pm.Data("y", np.ones(10))\n\n            alpha = pm.Normal("alpha", 0, 0.1)\n            beta = pm.Normal("beta", 0, 0.1)\n            mu = pm.Deterministic("mu", alpha + beta * x)\n            sigma = pm.HalfNormal("sigma", 0.1)\n            obs = pm.Normal("obs", mu, sigma, observed=y, shape=x.shape)\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            [obs],\n            vars_in_trace=[alpha, beta, sigma, mu],\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {obs}\n        assert {i.name for i in self.get_function_inputs(f)} == {"alpha", "beta", "sigma"}\n        assert {i.name for i in self.get_function_roots(f)} == {"x", "alpha", "beta", "sigma"}\n\n    def test_nested_observed_model(self):\n        with pm.Model() as model:\n            p = pm.Data("p", np.array([0.25, 0.5, 0.25]))\n            x = pm.Data("x", np.zeros(10))\n            y = pm.Data("y", np.ones(10))\n\n            category = pm.Categorical("category", p, observed=x)\n            beta = pm.Normal("beta", 0, 0.1, size=p.shape)\n            mu = pm.Deterministic("mu", beta[category])\n            sigma = pm.HalfNormal("sigma", 0.1)\n            obs = pm.Normal("obs", mu, sigma, observed=y, shape=mu.shape)\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=model.observed_RVs,\n            vars_in_trace=[beta, mu, sigma],\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {category, beta, obs}\n        assert {i.name for i in self.get_function_inputs(f)} == {"sigma"}\n        assert {i.name for i in self.get_function_roots(f)} == {"x", "p", "sigma"}\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=model.observed_RVs,\n            vars_in_trace=[beta, mu, sigma],\n            constant_data={"p": p.get_value()},\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {category, obs}\n        assert {i.name for i in self.get_function_inputs(f)} == {"beta", "sigma"}\n        assert {i.name for i in self.get_function_roots(f)} == {"x", "p", "beta", "sigma"}\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=model.observed_RVs,\n            vars_in_trace=[beta, mu, sigma],\n            constant_data={"p": p.get_value()},\n            basic_rvs=model.basic_RVs,\n            givens_dict={category: np.zeros(10, dtype=category.dtype)},\n        )\n        assert volatile_rvs == {obs}\n        assert {i.name for i in self.get_function_inputs(f)} == {"beta", "sigma"}\n        assert {i.name for i in self.get_function_roots(f)} == {\n            "x",\n            "p",\n            "category",\n            "beta",\n            "sigma",\n        }\n\n    def test_volatile_parameters(self):\n        with pm.Model() as model:\n            y = pm.Data("y", np.ones(10))\n            mu = pm.Normal("mu", 0, 1)\n            nested_mu = pm.Normal("nested_mu", mu, 1, size=10)\n            sigma = pm.HalfNormal("sigma", 1)\n            obs = pm.Normal("obs", nested_mu, sigma, observed=y, shape=nested_mu.shape)\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=model.observed_RVs,\n            vars_in_trace=[nested_mu, sigma],  # mu isn\'t in the trace and will be deemed volatile\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {mu, nested_mu, obs}\n        assert {i.name for i in self.get_function_inputs(f)} == {"sigma"}\n        assert {i.name for i in self.get_function_roots(f)} == {"sigma"}\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=model.observed_RVs,\n            vars_in_trace=[mu, nested_mu, sigma],\n            basic_rvs=model.basic_RVs,\n            givens_dict={\n                mu: pytensor.shared(np.array(1.0), name="mu")\n            },  # mu will be considered volatile because it\'s in givens\n        )\n        assert volatile_rvs == {nested_mu, obs}\n        assert {i.name for i in self.get_function_inputs(f)} == {"sigma"}\n        assert {i.name for i in self.get_function_roots(f)} == {"mu", "sigma"}\n\n    def test_mixture(self):\n        with pm.Model() as model:\n            w = pm.Dirichlet("w", a=np.ones(3), size=(5, 3))\n\n            mu = pm.Normal("mu", mu=np.arange(3), sigma=1)\n\n            components = pm.Normal.dist(mu=mu, sigma=1, size=w.shape)\n            mix_mu = pm.Mixture("mix_mu", w=w, comp_dists=components)\n            obs = pm.Normal("obs", mix_mu, 1, observed=np.ones((5, 3)))\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[obs],\n            vars_in_trace=[mix_mu, mu, w],\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {obs}\n        assert {i.name for i in self.get_function_inputs(f)} == {"w", "mu", "mix_mu"}\n        assert {i.name for i in self.get_function_roots(f)} == {"mix_mu"}\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[obs],\n            vars_in_trace=[mu, w],\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {mix_mu, obs}\n        assert {i.name for i in self.get_function_inputs(f)} == {"w", "mu"}\n        assert {i.name for i in self.get_function_roots(f)} == {"w", "mu"}\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[obs],\n            vars_in_trace=[mix_mu, mu],\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {w, mix_mu, obs}\n        assert {i.name for i in self.get_function_inputs(f)} == {"mu"}\n        assert {i.name for i in self.get_function_roots(f)} == {"mu"}\n\n    def test_censored(self):\n        with pm.Model() as model:\n            latent_mu = pm.Normal("latent_mu", mu=np.arange(3), sigma=1)\n            mu = pm.Censored("mu", pm.Normal.dist(mu=latent_mu, sigma=1), lower=-1, upper=1)\n            obs = pm.Normal("obs", mu, 1, observed=np.ones((10, 3)))\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[obs],\n            vars_in_trace=[latent_mu, mu],\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {obs}\n        assert {i.name for i in self.get_function_inputs(f)} == {"latent_mu", "mu"}\n        assert {i.name for i in self.get_function_roots(f)} == {"mu"}\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[obs],\n            vars_in_trace=[mu],\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {latent_mu, mu, obs}\n        assert {i.name for i in self.get_function_inputs(f)} == set()\n        assert {i.name for i in self.get_function_roots(f)} == set()\n\n    def test_lkj_cholesky_cov(self):\n        with pm.Model() as model:\n            mu = np.zeros(3)\n            sd_dist = pm.Exponential.dist(1.0, size=3)\n            chol, corr, stds = pm.LKJCholeskyCov(\n                "chol_packed", n=3, eta=2, sd_dist=sd_dist, compute_corr=True\n            )\n            chol_packed = model["chol_packed"]\n            chol = pm.Deterministic("chol", chol)\n            obs = pm.MvNormal("obs", mu=mu, chol=chol, observed=np.zeros(3))\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[obs],\n            vars_in_trace=[chol_packed, chol],\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {obs}\n        assert {i.name for i in self.get_function_inputs(f)} == {"chol_packed", "chol"}\n        assert {i.name for i in self.get_function_roots(f)} == {"chol"}\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[obs],\n            vars_in_trace=[chol_packed],\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {obs}\n        assert {i.name for i in self.get_function_inputs(f)} == {"chol_packed"}\n        assert {i.name for i in self.get_function_roots(f)} == {"chol_packed"}\n\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[obs],\n            vars_in_trace=[chol],\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {chol_packed, obs}\n        assert {i.name for i in self.get_function_inputs(f)} == set()\n        assert {i.name for i in self.get_function_roots(f)} == set()\n\n    def test_non_random_model_variable(self):\n        with pm.Model() as model:\n            # A user may register non-pure RandomVariables that can nevertheless be\n            # sampled, as long as a custom logprob is dispatched or we can infer\n            # its logprob (which is the case for `clip`)\n            y = pt.clip(pm.Normal.dist(), -1, 1)\n            y = model.register_rv(y, name="y")\n            y_abs = pm.Deterministic("y_abs", pt.abs(y))\n            obs = pm.Normal("obs", y_abs, observed=np.zeros(10))\n\n        # y_abs should be resampled even if in the trace, because the source y is missing\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[obs],\n            vars_in_trace=[y_abs],\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {y, obs}\n        assert {i.name for i in self.get_function_inputs(f)} == set()\n        assert {i.name for i in self.get_function_roots(f)} == set()\n\n    def test_mutable_coords_volatile(self):\n        rng = np.random.default_rng(seed=42)\n        data = rng.normal(loc=1, scale=0.2, size=(10, 3))\n        with pm.Model() as model:\n            model.add_coord("name", ["A", "B", "C"])\n            model.add_coord("obs", list(range(10, 20)))\n            offsets = pm.Data("offsets", rng.normal(0, 1, size=(10,)))\n            a = pm.Normal("a", mu=0, sigma=1, dims=["name"])\n            b = pm.Normal("b", mu=offsets, sigma=1)\n            mu = pm.Deterministic("mu", a + b[..., None], dims=["obs", "name"])\n            sigma = pm.HalfNormal("sigma", sigma=1, dims=["name"])\n\n            data = pm.Data(\n                "y_obs",\n                data,\n                dims=["obs", "name"],\n            )\n            y = pm.Normal("y", mu=mu, sigma=sigma, observed=data, dims=["obs", "name"])\n\n        # When no constant_data and constant_coords, all the dependent nodes will be volatile and\n        # resampled\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[y],\n            vars_in_trace=[a, b, mu, sigma],\n            basic_rvs=model.basic_RVs,\n        )\n        assert volatile_rvs == {y, a, b, sigma}\n        assert {i.name for i in self.get_function_inputs(f)} == set()\n        assert {i.name for i in self.get_function_roots(f)} == {"name", "obs", "offsets"}\n\n        # When the constant data has the same values as the shared data, offsets wont be volatile\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[y],\n            vars_in_trace=[a, b, mu, sigma],\n            basic_rvs=model.basic_RVs,\n            constant_data={"offsets": offsets.get_value()},\n        )\n        assert volatile_rvs == {y, a, sigma}\n        assert {i.name for i in self.get_function_inputs(f)} == {"b"}\n        assert {i.name for i in self.get_function_roots(f)} == {"b", "name", "obs"}\n\n        # When we declare constant_coords, the shared variables with matching names wont be volatile\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[y],\n            vars_in_trace=[a, b, mu, sigma],\n            basic_rvs=model.basic_RVs,\n            constant_coords={"name", "obs"},\n        )\n        assert volatile_rvs == {y, b}\n        assert {i.name for i in self.get_function_inputs(f)} == {"a", "sigma"}\n        assert {i.name for i in self.get_function_roots(f)} == {\n            "a",\n            "sigma",\n            "name",\n            "obs",\n            "offsets",\n        }\n\n        # When we have both constant_data and constant_coords, only y will be volatile\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[y],\n            vars_in_trace=[a, b, mu, sigma],\n            basic_rvs=model.basic_RVs,\n            constant_data={"offsets": offsets.get_value()},\n            constant_coords={"name", "obs"},\n        )\n        assert volatile_rvs == {y}\n        assert {i.name for i in self.get_function_inputs(f)} == {"a", "b", "mu", "sigma"}\n        assert {i.name for i in self.get_function_roots(f)} == {"mu", "sigma", "name", "obs"}\n\n        # When constant_data has different values than the shared variable, then\n        # offsets will be volatile\n        f, volatile_rvs = compile_forward_sampling_function(\n            outputs=[y],\n            vars_in_trace=[a, b, mu, sigma],\n            basic_rvs=model.basic_RVs,\n            constant_data={"offsets": offsets.get_value() + 1},\n            constant_coords={"name", "obs"},\n        )\n        assert volatile_rvs == {y, b}\n        assert {i.name for i in self.get_function_inputs(f)} == {"a", "sigma"}\n        assert {i.name for i in self.get_function_roots(f)} == {\n            "a",\n            "sigma",\n            "name",\n            "obs",\n            "offsets",\n        }\n\n    def test_length_coords_volatile(self):\n        with pm.Model() as model:\n            model.add_coord("trial", length=3)\n            x = pm.Normal("x", dims="trial")\n            y = pm.Deterministic("y", x.mean())\n\n        # Same coord length -- `x` is not volatile\n        trace_same_len = az_from_dict(\n            posterior={"x": [[[np.pi] * 3]]},\n            coords={"trial": range(3)},\n            dims={"x": ["trial"]},\n        )\n        with model:\n            pp_same_len = pm.sample_posterior_predictive(\n                trace_same_len, var_names=["y"]\n            ).posterior_predictive\n        assert pp_same_len["y"] == np.pi\n\n        # Coord length changed -- `x` is volatile\n        trace_diff_len = az_from_dict(\n            posterior={"x": [[[np.pi] * 2]]},\n            coords={"trial": range(2)},\n            dims={"x": ["trial"]},\n        )\n        with model:\n            pp_diff_len = pm.sample_posterior_predictive(\n                trace_diff_len, var_names=["y"]\n            ).posterior_predictive\n        assert pp_diff_len["y"] != np.pi\n\n        # Changing the dim length on the model itself\n        # -- `x` is volatile because trace has same len as original model\n        model.set_dim("trial", new_length=7)\n        with model:\n            pp_diff_len_model_set = pm.sample_posterior_predictive(\n                trace_same_len, var_names=["y"]\n            ).posterior_predictive\n        assert pp_diff_len_model_set["y"] != np.pi\n\n\nclass TestSamplePPC:\n    def test_normal_scalar(self):\n        nchains = 2\n        ndraws = 500\n        with pm.Model() as model:\n            mu = pm.Normal("mu", 0.0, 1.0)\n            a = pm.Normal("a", mu=mu, sigma=1, observed=0.0)\n            trace = pm.sample(\n                draws=ndraws,\n                chains=nchains,\n            )\n\n        with model:\n            # test list input\n            ppc0 = pm.sample_posterior_predictive(\n                10 * [model.initial_point()], return_inferencedata=False\n            )\n            assert "a" in ppc0\n            assert len(ppc0["a"][0]) == 10\n            # test empty ppc\n            ppc = pm.sample_posterior_predictive(trace, var_names=[], return_inferencedata=False)\n            assert len(ppc) == 0\n\n            # test empty ppc with extend_inferencedata\n            assert isinstance(trace, InferenceData)\n            ppc = pm.sample_posterior_predictive(trace, var_names=[], extend_inferencedata=True)\n            assert ppc is trace\n\n            # test keep_size parameter\n            ppc = pm.sample_posterior_predictive(trace, return_inferencedata=False)\n            assert ppc["a"].shape == (nchains, ndraws)\n\n            # test default case\n            random_state = np.random.default_rng(20160911)\n            idata_ppc = pm.sample_posterior_predictive(\n                trace, var_names=["a"], random_seed=random_state\n            )\n            ppc = idata_ppc.posterior_predictive\n            assert "a" in ppc\n            assert ppc["a"].shape == (nchains, ndraws)\n            # mu\'s standard deviation may have changed thanks to a\'s observed\n            _, pval = stats.kstest(\n                (ppc["a"] - trace.posterior["mu"]).values.flatten(), stats.norm(loc=0, scale=1).cdf\n            )\n            assert pval > 0.001\n\n    def test_normal_scalar_idata(self):\n        nchains = 2\n        ndraws = 500\n        with pm.Model() as model:\n            mu = pm.Normal("mu", 0.0, 1.0)\n            a = pm.Normal("a", mu=mu, sigma=1, observed=0.0)\n            with warnings.catch_warnings():\n                warnings.filterwarnings("ignore", "Tuning samples will be included.*", UserWarning)\n                trace = pm.sample(\n                    draws=ndraws,\n                    chains=nchains,\n                    return_inferencedata=False,\n                    discard_tuned_samples=False,\n                )\n\n        assert not isinstance(trace, InferenceData)\n\n        with model:\n            # test keep_size parameter and idata input\n            idata = pm.to_inference_data(trace)\n            assert isinstance(idata, InferenceData)\n\n            ppc = pm.sample_posterior_predictive(idata, return_inferencedata=False)\n            assert ppc["a"].shape == (nchains, ndraws)\n\n    def test_external_trace_det(self):\n        with pm.Model() as model:\n            mu = pm.Normal("mu", 0.0, 1.0)\n            a = pm.Normal("a", mu=mu, sigma=1, observed=0.0)\n            b = pm.Deterministic("b", a + 1)\n            trace = pm.sample(tune=50, draws=50, chains=1, compute_convergence_checks=False)\n\n        # test that trace is used in ppc\n        with pm.Model() as model_ppc:\n            mu = pm.Normal("mu", 0.0, 1.0)\n            a = pm.Normal("a", mu=mu, sigma=1)\n            c = pm.Deterministic("c", a + 1)\n\n        ppc = pm.sample_posterior_predictive(\n            trace=trace, model=model_ppc, return_inferencedata=False\n        )\n        assert list(ppc.keys()) == ["a", "c"]\n\n    def test_normal_vector(self):\n        with pm.Model() as model:\n            mu = pm.Normal("mu", 0.0, 1.0)\n            a = pm.Normal("a", mu=mu, sigma=1, observed=np.array([0.5, 0.2]))\n            trace = pm.sample(return_inferencedata=False, draws=12, chains=1)\n\n        with model:\n            # test list input\n            ppc0 = pm.sample_posterior_predictive(\n                10 * [model.initial_point()],\n                return_inferencedata=False,\n            )\n            ppc = pm.sample_posterior_predictive(trace, return_inferencedata=False, var_names=[])\n            assert len(ppc) == 0\n\n            ppc = pm.sample_posterior_predictive(trace, return_inferencedata=False)\n            assert ppc["a"].shape == (trace.nchains, len(trace), 2)\n            assert ppc0["a"].shape == (1, 10, 2)\n\n    def test_normal_vector_idata(self):\n        with pm.Model() as model:\n            mu = pm.Normal("mu", 0.0, 1.0)\n            a = pm.Normal("a", mu=mu, sigma=1, observed=np.array([0.5, 0.2]))\n            trace = pm.sample(return_inferencedata=False)\n\n        assert not isinstance(trace, InferenceData)\n\n        with model:\n            # test keep_size parameter with inference data as input...\n            idata = pm.to_inference_data(trace)\n            assert isinstance(idata, InferenceData)\n\n            ppc = pm.sample_posterior_predictive(idata, return_inferencedata=False)\n            assert ppc["a"].shape == (trace.nchains, len(trace), 2)\n\n    def test_exceptions(self):\n        with pm.Model() as model:\n            mu = pm.Normal("mu", 0.0, 1.0)\n            a = pm.Normal("a", mu=mu, sigma=1, observed=np.array([0.5, 0.2]))\n            idata = pm.sample(idata_kwargs={"log_likelihood": False})\n\n        with model:\n            # test wrong type argument\n            bad_trace = {"mu": stats.norm.rvs(size=1000)}\n            with pytest.raises(TypeError, match="type for `trace`"):\n                ppc = pm.sample_posterior_predictive(bad_trace)\n\n    def test_sum_normal(self):\n        with pm.Model() as model:\n            a = pm.Normal("a", sigma=0.2)\n            b = pm.Normal("b", mu=a)\n            idata = pm.sample(draws=1000, chains=1)\n\n        with model:\n            # test list input\n            ppc0 = pm.sample_posterior_predictive(\n                10 * [model.initial_point()], return_inferencedata=False\n            )\n            assert ppc0 == {}\n            ppc = pm.sample_posterior_predictive(idata, return_inferencedata=False, var_names=["b"])\n            assert len(ppc) == 1\n            assert ppc["b"].shape == (\n                1,\n                1000,\n            )\n            scale = np.sqrt(1 + 0.2**2)\n            _, pval = stats.kstest(ppc["b"].flatten(), stats.norm(scale=scale).cdf)\n            assert pval > 0.001\n\n    def test_model_not_drawable_prior(self, seeded_test):\n        data = np.random.poisson(lam=10, size=200)\n        model = pm.Model()\n        with model:\n            mu = pm.HalfFlat("sigma")\n            pm.Poisson("foo", mu=mu, observed=data)\n            with pytensor.config.change_flags(mode=fast_unstable_sampling_mode):\n                with warnings.catch_warnings():\n                    warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n                    idata = pm.sample(tune=10, draws=40, chains=1)\n\n        with model:\n            with pytest.raises(NotImplementedError) as excinfo:\n                pm.sample_prior_predictive(50)\n            assert "Cannot sample" in str(excinfo.value)\n            samples = pm.sample_posterior_predictive(idata, return_inferencedata=False)\n            assert samples["foo"].shape == (1, 40, 200)\n\n    def test_model_shared_variable(self):\n        rng = np.random.default_rng(9832)\n\n        x = rng.normal(size=100)\n        y = x > 0\n        x_shared = pytensor.shared(x)\n        y_shared = pytensor.shared(y)\n        samples = 100\n        with pm.Model() as model:\n            coeff = pm.Normal("x", mu=0, sigma=1)\n            logistic = pm.Deterministic("p", pm.math.sigmoid(coeff * x_shared))\n\n            obs = pm.Bernoulli("obs", p=logistic, observed=y_shared)\n            trace = pm.sample(\n                samples,\n                chains=1,\n                return_inferencedata=False,\n                compute_convergence_checks=False,\n                random_seed=rng,\n            )\n\n        x_shared.set_value([-1, 0, 1.0])\n        y_shared.set_value([0, 0, 0])\n\n        with model:\n            post_pred = pm.sample_posterior_predictive(\n                trace, return_inferencedata=False, var_names=["p", "obs"]\n            )\n\n        expected_p = np.array([[logistic.eval({coeff: val}) for val in trace["x"][:samples]]])\n        assert post_pred["obs"].shape == (1, samples, 3)\n        npt.assert_allclose(post_pred["p"], expected_p)\n\n    def test_deterministic_of_observed(self):\n        rng = np.random.default_rng(8442)\n\n        meas_in_1 = pm.pytensorf.floatX(2 + 4 * rng.normal(size=10))\n        meas_in_2 = pm.pytensorf.floatX(5 + 4 * rng.normal(size=10))\n        nchains = 2\n        with pm.Model() as model:\n            mu_in_1 = pm.Normal("mu_in_1", 0, 2)\n            sigma_in_1 = pm.HalfNormal("sd_in_1", 1)\n            mu_in_2 = pm.Normal("mu_in_2", 0, 2)\n            sigma_in_2 = pm.HalfNormal("sd__in_2", 1)\n\n            in_1 = pm.Normal("in_1", mu_in_1, sigma_in_1, observed=meas_in_1)\n            in_2 = pm.Normal("in_2", mu_in_2, sigma_in_2, observed=meas_in_2)\n            out_diff = in_1 + in_2\n            pm.Deterministic("out", out_diff)\n\n            with pytensor.config.change_flags(mode=fast_unstable_sampling_mode):\n                trace = pm.sample(\n                    tune=100,\n                    draws=100,\n                    chains=nchains,\n                    step=pm.Metropolis(),\n                    return_inferencedata=False,\n                    compute_convergence_checks=False,\n                    random_seed=rng,\n                )\n\n            rtol = 1e-5 if pytensor.config.floatX == "float64" else 1e-4\n\n            ppc = pm.sample_posterior_predictive(\n                return_inferencedata=False,\n                model=model,\n                trace=trace,\n                random_seed=0,\n                var_names=[var.name for var in (model.deterministics + model.basic_RVs)],\n            )\n\n            npt.assert_allclose(ppc["in_1"] + ppc["in_2"], ppc["out"], rtol=rtol)\n\n    def test_deterministic_of_observed_modified_interface(self):\n        rng = np.random.default_rng(4982)\n\n        meas_in_1 = pm.pytensorf.floatX(2 + 4 * rng.normal(size=100))\n        meas_in_2 = pm.pytensorf.floatX(5 + 4 * rng.normal(size=100))\n        with pm.Model() as model:\n            mu_in_1 = pm.Normal("mu_in_1", 0, 1, initval=0)\n            sigma_in_1 = pm.HalfNormal("sd_in_1", 1, initval=1)\n            mu_in_2 = pm.Normal("mu_in_2", 0, 1, initval=0)\n            sigma_in_2 = pm.HalfNormal("sd__in_2", 1, initval=1)\n\n            in_1 = pm.Normal("in_1", mu_in_1, sigma_in_1, observed=meas_in_1)\n            in_2 = pm.Normal("in_2", mu_in_2, sigma_in_2, observed=meas_in_2)\n            out_diff = in_1 + in_2\n            pm.Deterministic("out", out_diff)\n\n            with pytensor.config.change_flags(mode=fast_unstable_sampling_mode):\n                trace = pm.sample(\n                    tune=100,\n                    draws=100,\n                    step=pm.Metropolis(),\n                    return_inferencedata=False,\n                    compute_convergence_checks=False,\n                    random_seed=rng,\n                )\n            varnames = [v for v in trace.varnames if v != "out"]\n            ppc_trace = [\n                dict(zip(varnames, row)) for row in zip(*(trace.get_values(v) for v in varnames))\n            ]\n            ppc = pm.sample_posterior_predictive(\n                return_inferencedata=False,\n                model=model,\n                trace=ppc_trace,\n                var_names=[x.name for x in (model.deterministics + model.basic_RVs)],\n            )\n\n            rtol = 1e-5 if pytensor.config.floatX == "float64" else 1e-3\n            npt.assert_allclose(ppc["in_1"] + ppc["in_2"], ppc["out"], rtol=rtol)\n\n    def test_variable_type(self):\n        with pm.Model() as model:\n            mu = pm.HalfNormal("mu", 1)\n            a = pm.Normal("a", mu=mu, sigma=2, observed=np.array([1, 2]))\n            b = pm.Poisson("b", mu, observed=np.array([1, 2]))\n            with pytensor.config.change_flags(mode=fast_unstable_sampling_mode):\n                trace = pm.sample(\n                    tune=10, draws=10, compute_convergence_checks=False, return_inferencedata=False\n                )\n\n        with model:\n            ppc = pm.sample_posterior_predictive(trace, return_inferencedata=False)\n            assert ppc["a"].dtype.kind == "f"\n            assert ppc["b"].dtype.kind == "i"\n\n    def test_potentials_warning(self):\n        warning_msg = "The effect of Potentials on other parameters is ignored during"\n        with pm.Model() as m:\n            a = pm.Normal("a", 0, 1)\n            p = pm.Potential("p", a + 1)\n            obs = pm.Normal("obs", a, 1, observed=5)\n\n        trace = az_from_dict({"a": np.random.rand(5)})\n        with m:\n            with pytest.warns(UserWarning, match=warning_msg):\n                pm.sample_posterior_predictive(trace)\n\n    def test_idata_extension(self):\n        """Testing if sample_posterior_predictive() extends inferenceData"""\n\n        with pm.Model() as model:\n            mu = pm.Normal("mu", 0.0, 1.0)\n            a = pm.Normal("a", mu=mu, sigma=1, observed=[0.0, 1.0])\n            idata = pm.sample(tune=10, draws=10, compute_convergence_checks=False)\n\n        base_test_dict = {\n            "posterior": ["mu", "~a"],\n            "sample_stats": ["diverging", "lp"],\n            "observed_data": ["a"],\n        }\n        test_dict = {"~posterior_predictive": [], "~predictions": [], **base_test_dict}\n        fails = check_multiple_attrs(test_dict, idata)\n        assert not fails\n\n        # extending idata with in-sample ppc\n        with model:\n            pm.sample_posterior_predictive(idata, extend_inferencedata=True)\n        # test addition\n        test_dict = {"posterior_predictive": ["a"], "~predictions": [], **base_test_dict}\n        fails = check_multiple_attrs(test_dict, idata)\n        assert not fails\n\n        # extending idata with out-of-sample ppc\n        with model:\n            pm.sample_posterior_predictive(idata, extend_inferencedata=True, predictions=True)\n        # test addition\n        test_dict = {"posterior_predictive": ["a"], "predictions": ["a"], **base_test_dict}\n        fails = check_multiple_attrs(test_dict, idata)\n        assert not fails\n\n    @pytest.mark.parametrize("multitrace", [False, True])\n    def test_deterministics_out_of_idata(self, multitrace):\n        draws = 10\n        chains = 2\n        coords = {"draw": range(draws), "chain": range(chains)}\n        ds = xr.Dataset(\n            {\n                "a": xr.DataArray(\n                    [[0] * draws] * chains,\n                    coords=coords,\n                    dims=["chain", "draw"],\n                )\n            },\n            coords=coords,\n        )\n        with pm.Model() as m:\n            a = pm.Normal("a")\n            if multitrace:\n                straces = []\n                for chain in ds.chain:\n                    strace = pm.backends.NDArray(model=m, vars=[a])\n                    strace.setup(len(ds.draw), int(chain))\n                    strace.values = {"a": ds.a.sel(chain=chain).data}\n                    strace.draw_idx = len(ds.draw)\n                    straces.append(strace)\n                trace = MultiTrace(straces)\n            else:\n                trace = ds\n\n            d = pm.Deterministic("d", a - 4)\n            pm.Normal("c", d, sigma=0.01)\n            ppc = pm.sample_posterior_predictive(trace, var_names="c", return_inferencedata=True)\n        assert np.all(np.abs(ppc.posterior_predictive.c + 4) <= 0.1)\n\n    def test_logging_sampled_basic_rvs_prior(self, caplog):\n        with pm.Model() as m:\n            x = pm.Normal("x")\n            y = pm.Deterministic("y", x + 1)\n            z = pm.Normal("z", y, observed=0)\n\n        # all volatile RVs in model\n        with m:\n            pm.sample_prior_predictive(draws=1)\n        assert caplog.record_tuples == [("pymc.sampling.forward", logging.INFO, "Sampling: [x, z]")]\n        caplog.clear()\n\n        # `x` has no dependencies so will be sampled by itself\n        with m:\n            pm.sample_prior_predictive(draws=1, var_names=["x"])\n        assert caplog.record_tuples == [("pymc.sampling.forward", logging.INFO, "Sampling: [x]")]\n        caplog.clear()\n\n        # `z` depends on `x`\n        with m:\n            pm.sample_prior_predictive(draws=1, var_names=["z"])\n        assert caplog.record_tuples == [("pymc.sampling.forward", logging.INFO, "Sampling: [x, z]")]\n        caplog.clear()\n\n    def test_logging_sampled_basic_rvs_posterior(self, caplog):\n        with pm.Model() as m:\n            x = pm.Normal("x")\n            x_det = pm.Deterministic("x_det", x + 1)\n            y = pm.Normal("y", x_det)\n            z = pm.Normal("z", y, observed=0)\n\n        idata = az_from_dict(posterior={"x": np.zeros(5), "x_det": np.ones(5), "y": np.ones(5)})\n        with m:\n            pm.sample_posterior_predictive(idata)\n        assert caplog.record_tuples == [("pymc.sampling.forward", logging.INFO, "Sampling: [z]")]\n        caplog.clear()\n\n        with m:\n            pm.sample_posterior_predictive(idata, var_names=["y", "z"])\n        assert caplog.record_tuples == [("pymc.sampling.forward", logging.INFO, "Sampling: [y, z]")]\n        caplog.clear()\n\n        # Resampling `x` will force resampling of `y`, even if it is in trace\n        with m:\n            pm.sample_posterior_predictive(idata, var_names=["x", "z"])\n        assert caplog.record_tuples == [\n            ("pymc.sampling.forward", logging.INFO, "Sampling: [x, y, z]")\n        ]\n        caplog.clear()\n\n        # Missing deterministic `x_det` does not show in the log, even if it is being\n        # recomputed, only `y` RV shows\n        idata = az_from_dict(posterior={"x": np.zeros(5)})\n        with m:\n            pm.sample_posterior_predictive(idata)\n        assert caplog.record_tuples == [("pymc.sampling.forward", logging.INFO, "Sampling: [y, z]")]\n        caplog.clear()\n\n        # Missing deterministic `x_det` does not cause recomputation of downstream `y` RV\n        idata = az_from_dict(posterior={"x": np.zeros(5), "y": np.ones(5)})\n        with m:\n            pm.sample_posterior_predictive(idata)\n        assert caplog.record_tuples == [("pymc.sampling.forward", logging.INFO, "Sampling: [z]")]\n        caplog.clear()\n\n        # Missing `x` causes sampling of downstream `y` RV, even if it is present in trace\n        idata = az_from_dict(posterior={"y": np.ones(5)})\n        with m:\n            pm.sample_posterior_predictive(idata)\n        assert caplog.record_tuples == [\n            ("pymc.sampling.forward", logging.INFO, "Sampling: [x, y, z]")\n        ]\n        caplog.clear()\n\n    def test_logging_sampled_basic_rvs_posterior_deterministic(self, caplog):\n        with pm.Model() as m:\n            x = pm.Normal("x")\n            x_det = pm.Deterministic("x_det", x + 1)\n            y = pm.Normal("y", x_det)\n            z = pm.Normal("z", y, observed=0)\n\n        # Explicit resampling a deterministic will lead to resampling of downstream RV `y`\n        # This behavior could change in the future as the posterior of `y` is still valid\n        idata = az_from_dict(posterior={"x": np.zeros(5), "x_det": np.ones(5), "y": np.ones(5)})\n        with m:\n            pm.sample_posterior_predictive(idata, var_names=["x_det", "z"])\n        assert caplog.record_tuples == [("pymc.sampling.forward", logging.INFO, "Sampling: [y, z]")]\n        caplog.clear()\n\n    @staticmethod\n    def make_mock_model():\n        rng = np.random.default_rng(seed=42)\n        data = rng.normal(loc=1, scale=0.2, size=(10, 3))\n        with pm.Model() as model:\n            model.add_coord("name", ["A", "B", "C"])\n            model.add_coord("obs", list(range(10, 20)))\n            offsets = pm.Data("offsets", rng.normal(0, 1, size=(10,)))\n            a = pm.Normal("a", mu=0, sigma=1, dims=["name"])\n            b = pm.Normal("b", mu=offsets, sigma=1)\n            mu = pm.Deterministic("mu", a + b[..., None], dims=["obs", "name"])\n            sigma = pm.HalfNormal("sigma", sigma=1, dims=["name"])\n\n            data = pm.Data(\n                "y_obs",\n                data,\n                dims=["obs", "name"],\n            )\n            pm.Normal("y", mu=mu, sigma=sigma, observed=data, dims=["obs", "name"])\n        return model\n\n    @pytest.fixture(scope="class")\n    def mock_multitrace(self):\n        with self.make_mock_model():\n            trace = pm.sample(\n                draws=10,\n                tune=10,\n                chains=2,\n                progressbar=False,\n                compute_convergence_checks=False,\n                return_inferencedata=False,\n                random_seed=42,\n            )\n        return trace\n\n    @pytest.fixture(scope="class", params=["MultiTrace", "InferenceData", "Dataset"])\n    def mock_sample_results(self, request, mock_multitrace):\n        kind = request.param\n        trace = mock_multitrace\n        # We rebuild the class to ensure that all dimensions, data and coords start out\n        # the same across params values\n        model = self.make_mock_model()\n        if kind == "MultiTrace":\n            return kind, trace, model\n        else:\n            idata = pm.to_inference_data(\n                trace,\n                save_warmup=False,\n                model=model,\n                log_likelihood=False,\n            )\n            if kind == "Dataset":\n                return kind, idata.posterior, model\n            else:\n                return kind, idata, model\n\n    def test_logging_sampled_basic_rvs_posterior_mutable(self, mock_sample_results, caplog):\n        kind, samples, model = mock_sample_results\n        with model:\n            pm.sample_posterior_predictive(samples)\n        if kind == "MultiTrace":\n            # MultiTrace will only have the actual MCMC posterior samples but no information on\n            # the Data and coordinate values, so it will always assume they are volatile\n            # and resample their descendants\n            assert caplog.record_tuples == [\n                ("pymc.sampling.forward", logging.INFO, "Sampling: [a, b, sigma, y]")\n            ]\n            caplog.clear()\n        elif kind == "InferenceData":\n            # InferenceData has all MCMC posterior samples and the values for both coordinates and\n            # data containers. This enables it to see that no data has changed and it should only\n            # resample the observed variable\n            assert caplog.record_tuples == [\n                ("pymc.sampling.forward", logging.INFO, "Sampling: [y]")\n            ]\n            caplog.clear()\n        elif kind == "Dataset":\n            # Dataset has all MCMC posterior samples and the values of the coordinates. This\n            # enables it to see that the coordinates have not changed, but the Data is\n            # assumed volatile by default\n            assert caplog.record_tuples == [\n                ("pymc.sampling.forward", logging.INFO, "Sampling: [b, y]")\n            ]\n            caplog.clear()\n\n        original_offsets = model["offsets"].get_value()\n        with model:\n            # Changing the Data values. This will only be picked up by InferenceData\n            pm.set_data({"offsets": original_offsets + 1})\n            pm.sample_posterior_predictive(samples)\n        if kind == "MultiTrace":\n            assert caplog.record_tuples == [\n                ("pymc.sampling.forward", logging.INFO, "Sampling: [a, b, sigma, y]")\n            ]\n            caplog.clear()\n        elif kind == "InferenceData":\n            assert caplog.record_tuples == [\n                ("pymc.sampling.forward", logging.INFO, "Sampling: [b, y]")\n            ]\n            caplog.clear()\n        elif kind == "Dataset":\n            assert caplog.record_tuples == [\n                ("pymc.sampling.forward", logging.INFO, "Sampling: [b, y]")\n            ]\n            caplog.clear()\n\n        with model:\n            # Changing the mutable coordinates. This will be picked up by InferenceData and Dataset\n            model.set_dim("name", new_length=4, coord_values=["D", "E", "F", "G"])\n            pm.set_data({"offsets": original_offsets, "y_obs": np.zeros((10, 4))})\n            pm.sample_posterior_predictive(samples)\n        if kind == "MultiTrace":\n            assert caplog.record_tuples == [\n                ("pymc.sampling.forward", logging.INFO, "Sampling: [a, b, sigma, y]")\n            ]\n            caplog.clear()\n        elif kind == "InferenceData":\n            assert caplog.record_tuples == [\n                ("pymc.sampling.forward", logging.INFO, "Sampling: [a, sigma, y]")\n            ]\n            caplog.clear()\n        elif kind == "Dataset":\n            assert caplog.record_tuples == [\n                ("pymc.sampling.forward", logging.INFO, "Sampling: [a, b, sigma, y]")\n            ]\n            caplog.clear()\n\n        with model:\n            # Changing the mutable coordinate values, but not shape, and also changing Data.\n            # This will trigger resampling of all variables\n            model.set_dim("name", new_length=3, coord_values=["A", "B", "D"])\n            pm.set_data({"offsets": original_offsets + 1, "y_obs": np.zeros((10, 3))})\n            pm.sample_posterior_predictive(samples)\n        if kind == "MultiTrace":\n            assert caplog.record_tuples == [\n                ("pymc.sampling.forward", logging.INFO, "Sampling: [a, b, sigma, y]")\n            ]\n            caplog.clear()\n        elif kind == "InferenceData":\n            assert caplog.record_tuples == [\n                ("pymc.sampling.forward", logging.INFO, "Sampling: [a, b, sigma, y]")\n            ]\n            caplog.clear()\n        elif kind == "Dataset":\n            assert caplog.record_tuples == [\n                ("pymc.sampling.forward", logging.INFO, "Sampling: [a, b, sigma, y]")\n            ]\n            caplog.clear()\n\n    def test_observed_data_needed_in_pp(self):\n        # Model where y_data is not part of the generative graph.\n        # It shouldn\'t be needed to set a dummy value for posterior predictive sampling\n\n        with pm.Model(coords={"trial": range(5), "feature": range(3)}) as m:\n            x_data = pm.Data("x_data", np.random.normal(size=(5, 3)), dims=("trial", "feat"))\n            y_data = pm.Data("y_data", np.random.normal(size=(5,)), dims=("trial",))\n            sigma = pm.HalfNormal("sigma")\n            mu = x_data.sum(-1)\n            pm.Normal("y", mu=mu, sigma=sigma, observed=y_data, shape=mu.shape, dims=("trial",))\n\n            prior = pm.sample_prior_predictive(draws=25).prior\n\n        fake_idata = InferenceData(posterior=prior)\n\n        new_coords = {"trial": range(2), "feature": range(3)}\n        new_x_data = np.random.normal(size=(2, 3))\n        with m:\n            pm.set_data(\n                {\n                    "x_data": new_x_data,\n                },\n                coords=new_coords,\n            )\n            pp = pm.sample_posterior_predictive(fake_idata, predictions=True, progressbar=False)\n        assert pp.predictions["y"].shape == (1, 25, 2)\n\n        # In this case y_data is part of the generative graph, so we must set it to a compatible value\n        with pm.Model(coords={"trial": range(5), "feature": range(3)}) as m:\n            x_data = pm.Data("x_data", np.random.normal(size=(5, 3)), dims=("trial", "feat"))\n            y_data = pm.Data("y_data", np.random.normal(size=(5,)), dims=("trial",))\n            sigma = pm.HalfNormal("sigma")\n            mu = (y_data.sum() * x_data).sum(-1)\n            pm.Normal("y", mu=mu, sigma=sigma, observed=y_data, shape=mu.shape, dims=("trial",))\n\n            prior = pm.sample_prior_predictive(draws=25).prior\n\n        fake_idata = InferenceData(posterior=prior)\n\n        with m:\n            pm.set_data({"x_data": new_x_data}, coords=new_coords)\n            with pytest.raises(ValueError, match="conflicting sizes for dimension \'trial\'"):\n                pm.sample_posterior_predictive(fake_idata, predictions=True, progressbar=False)\n\n        new_y_data = np.random.normal(size=(2,))\n        with m:\n            pm.set_data({"y_data": new_y_data})\n        assert pp.predictions["y"].shape == (1, 25, 2)\n\n\n@pytest.fixture(scope="class")\ndef point_list_arg_bug_fixture() -> tuple[pm.Model, pm.backends.base.MultiTrace]:\n    with pm.Model() as pmodel:\n        n = pm.Normal("n")\n        trace = pm.sample(return_inferencedata=False)\n\n    with pmodel:\n        d = pm.Deterministic("d", n * 4)\n    return pmodel, trace\n\n\nclass TestSamplePriorPredictive:\n    def test_ignores_observed(self, seeded_test):\n        observed = np.random.normal(10, 1, size=200)\n        with pm.Model():\n            # Use a prior that\'s way off to show we\'re ignoring the observed variables\n            observed_data = pm.Data("observed_data", observed)\n            mu = pm.Normal("mu", mu=-100, sigma=1)\n            positive_mu = pm.Deterministic("positive_mu", np.abs(mu))\n            z = -1 - positive_mu\n            pm.Normal("x_obs", mu=z, sigma=1, observed=observed_data)\n            prior = pm.sample_prior_predictive(return_inferencedata=False)\n\n        assert "observed_data" not in prior\n        assert (prior["mu"] < -90).all()\n        assert (prior["positive_mu"] > 90).all()\n        assert (prior["x_obs"] < -90).all()\n        assert prior["x_obs"].shape == (500, 200)\n        npt.assert_array_almost_equal(prior["positive_mu"], np.abs(prior["mu"]), decimal=4)\n\n    def test_respects_shape(self):\n        for shape in (2, (2,), (10, 2), (10, 10)):\n            with pm.Model():\n                mu = pm.Gamma("mu", 3, 1, size=1)\n                goals = pm.Poisson("goals", mu, size=shape)\n                trace1 = pm.sample_prior_predictive(\n                    10, return_inferencedata=False, var_names=["mu", "mu", "goals"]\n                )\n                trace2 = pm.sample_prior_predictive(\n                    10, return_inferencedata=False, var_names=["mu", "goals"]\n                )\n            if shape == 2:  # want to test shape as an int\n                shape = (2,)\n            assert trace1["goals"].shape == (10, *shape)\n            assert trace2["goals"].shape == (10, *shape)\n\n    def test_multivariate(self):\n        with pm.Model():\n            m = pm.Multinomial("m", n=5, p=np.array([0.25, 0.25, 0.25, 0.25]))\n            trace = pm.sample_prior_predictive(10)\n\n        assert trace.prior["m"].shape == (1, 10, 4)\n\n    def test_multivariate2(self, seeded_test):\n        # Added test for issue #3271\n        mn_data = np.random.multinomial(n=100, pvals=[1 / 6.0] * 6, size=10)\n        with pm.Model() as dm_model:\n            probs = pm.Dirichlet("probs", a=np.ones(6))\n            obs = pm.Multinomial("obs", n=100, p=probs, observed=mn_data)\n            with pytensor.config.change_flags(mode=fast_unstable_sampling_mode):\n                burned_trace = pm.sample(\n                    tune=10,\n                    draws=20,\n                    chains=1,\n                    return_inferencedata=False,\n                    compute_convergence_checks=False,\n                )\n        sim_priors = pm.sample_prior_predictive(\n            return_inferencedata=False, draws=20, model=dm_model\n        )\n        sim_ppc = pm.sample_posterior_predictive(\n            burned_trace, return_inferencedata=False, model=dm_model\n        )\n        assert sim_priors["probs"].shape == (20, 6)\n        assert sim_priors["obs"].shape == (20, *mn_data.shape)\n        assert sim_ppc["obs"].shape == (1, 20, *mn_data.shape)\n\n    def test_layers(self):\n        with pm.Model() as model:\n            a = pm.Uniform("a", lower=0, upper=1, size=10)\n            b = pm.Binomial("b", n=1, p=a, size=10)\n\n        b_sampler = compile([], b, mode="FAST_RUN", random_seed=232093)\n        avg = np.stack([b_sampler() for i in range(10000)]).mean(0)\n        npt.assert_array_almost_equal(avg, 0.5 * np.ones((10,)), decimal=2)\n\n    def test_transformed(self, seeded_test):\n        n = 18\n        at_bats = 45 * np.ones(n, dtype=int)\n        hits = np.random.randint(1, 40, size=n, dtype=int)\n        draws = 50\n\n        with pm.Model() as model:\n            phi = pm.Beta("phi", alpha=1.0, beta=1.0)\n\n            kappa_log = pm.Exponential("logkappa", lam=5.0)\n            kappa = pm.Deterministic("kappa", pt.exp(kappa_log))\n\n            thetas = pm.Beta("thetas", alpha=phi * kappa, beta=(1.0 - phi) * kappa, size=n)\n\n            y = pm.Binomial("y", n=at_bats, p=thetas, observed=hits)\n            gen = pm.sample_prior_predictive(draws)\n\n        assert gen.prior["phi"].shape == (1, draws)\n        assert gen.prior_predictive["y"].shape == (1, draws, n)\n        assert "thetas" in gen.prior.data_vars\n\n    def test_shared(self, seeded_test):\n        n1 = 10\n        obs = shared(np.random.rand(n1) < 0.5)\n        draws = 50\n\n        with pm.Model() as m:\n            p = pm.Beta("p", 1.0, 1.0)\n            y = pm.Bernoulli("y", p, observed=obs)\n            o = pm.Deterministic("o", obs)\n            gen1 = pm.sample_prior_predictive(draws)\n\n        assert gen1.prior_predictive["y"].shape == (1, draws, n1)\n        assert gen1.prior["o"].shape == (1, draws, n1)\n\n        n2 = 20\n        obs.set_value(np.random.rand(n2) < 0.5)\n        with m:\n            gen2 = pm.sample_prior_predictive(draws)\n\n        assert gen2.prior_predictive["y"].shape == (1, draws, n2)\n        assert gen2.prior["o"].shape == (1, draws, n2)\n\n    def test_density_dist(self, seeded_test):\n        obs = np.random.normal(-1, 0.1, size=10)\n        with pm.Model():\n            mu = pm.Normal("mu", 0, 1)\n            sigma = pm.HalfNormal("sigma", 1e-6)\n            a = pm.CustomDist(\n                "a",\n                mu,\n                sigma,\n                random=lambda mu, sigma, rng=None, size=None: rng.normal(\n                    loc=mu, scale=sigma, size=size\n                ),\n                observed=obs,\n            )\n            prior = pm.sample_prior_predictive(return_inferencedata=False)\n\n        npt.assert_almost_equal((prior["a"] - prior["mu"][..., None]).mean(), 0, decimal=3)\n\n    def test_shape_edgecase(self):\n        with pm.Model():\n            mu = pm.Normal("mu", size=5)\n            sigma = pm.Uniform("sigma", lower=2, upper=3)\n            x = pm.Normal("x", mu=mu, sigma=sigma, size=5)\n            prior = pm.sample_prior_predictive(10)\n        assert prior.prior["mu"].shape == (1, 10, 5)\n\n    def test_zeroinflatedpoisson(self):\n        with pm.Model():\n            mu = pm.Beta("mu", alpha=1, beta=1)\n            psi = pm.HalfNormal("psi", sigma=1)\n            pm.ZeroInflatedPoisson("suppliers", psi=psi, mu=mu, size=20)\n            gen_data = pm.sample_prior_predictive(draws=5000)\n            assert gen_data.prior["mu"].shape == (1, 5000)\n            assert gen_data.prior["psi"].shape == (1, 5000)\n            assert gen_data.prior["suppliers"].shape == (1, 5000, 20)\n\n    def test_potentials_warning(self):\n        warning_msg = "The effect of Potentials on other parameters is ignored during"\n        with pm.Model() as m:\n            a = pm.Normal("a", 0, 1)\n            p = pm.Potential("p", a + 1)\n\n        with m:\n            with pytest.warns(UserWarning, match=warning_msg):\n                pm.sample_prior_predictive(draws=5)\n\n    def test_transformed_vars_not_supported(self):\n        with pm.Model() as model:\n            ub = pm.HalfNormal("ub", 10)\n            x = pm.Uniform("x", 0, ub)\n\n            with pytest.raises(ValueError, match="Unrecognized var_names"):\n                pm.sample_prior_predictive(var_names=["ub", "ub_log__", "x", "x_interval__"])\n\n    def test_issue_4490(self):\n        # Test that samples do not depend on var_name order or, more fundamentally,\n        # that they do not depend on the set order used inside `sample_prior_predictive`\n        seed = 4490\n        with pm.Model() as m1:\n            a = pm.Normal("a")\n            b = pm.Normal("b")\n            c = pm.Normal("c")\n            d = pm.Normal("d")\n            prior1 = pm.sample_prior_predictive(\n                draws=1, var_names=["a", "b", "c", "d"], random_seed=seed\n            )\n\n        with pm.Model() as m2:\n            a = pm.Normal("a")\n            b = pm.Normal("b")\n            c = pm.Normal("c")\n            d = pm.Normal("d")\n            prior2 = pm.sample_prior_predictive(\n                draws=1, var_names=["b", "a", "d", "c"], random_seed=seed\n            )\n\n        assert prior1.prior["a"] == prior2.prior["a"]\n        assert prior1.prior["b"] == prior2.prior["b"]\n        assert prior1.prior["c"] == prior2.prior["c"]\n        assert prior1.prior["d"] == prior2.prior["d"]\n\n    def test_pytensor_function_kwargs(self):\n        sharedvar = pytensor.shared(0)\n        with pm.Model() as m:\n            x = pm.DiracDelta("x", 0)\n            y = pm.Deterministic("y", x + sharedvar)\n\n            prior = pm.sample_prior_predictive(\n                draws=5,\n                return_inferencedata=False,\n                compile_kwargs={\n                    "mode": Mode("py"),\n                    "updates": {sharedvar: sharedvar + 1},\n                },\n            )\n\n        assert np.all(prior["y"] == np.arange(5))\n\n\nclass TestSamplePosteriorPredictive:\n    def test_point_list_arg_bug_spp(self, point_list_arg_bug_fixture):\n        pmodel, trace = point_list_arg_bug_fixture\n        with pmodel:\n            pp = pm.sample_posterior_predictive(\n                [trace[15]], return_inferencedata=False, var_names=["d"]\n            )\n\n    def test_sample_from_xarray_prior(self, point_list_arg_bug_fixture):\n        pmodel, trace = point_list_arg_bug_fixture\n\n        with pmodel:\n            prior = pm.sample_prior_predictive(\n                draws=20,\n                return_inferencedata=False,\n            )\n            idat = pm.to_inference_data(trace, prior=prior)\n\n        with pmodel:\n            pp = pm.sample_posterior_predictive(\n                idat.prior, return_inferencedata=False, var_names=["d"]\n            )\n\n    def test_sample_from_xarray_posterior(self, point_list_arg_bug_fixture):\n        pmodel, trace = point_list_arg_bug_fixture\n        with pmodel:\n            idat = pm.to_inference_data(trace)\n            pp = pm.sample_posterior_predictive(idat.posterior, var_names=["d"])\n\n    def test_pytensor_function_kwargs(self):\n        sharedvar = pytensor.shared(0)\n        with pm.Model() as m:\n            x = pm.DiracDelta("x", 0.0)\n            y = pm.Deterministic("y", x + sharedvar)\n\n            pp = pm.sample_posterior_predictive(\n                trace=az_from_dict({"x": np.arange(5)}),\n                var_names=["y"],\n                return_inferencedata=False,\n                compile_kwargs={\n                    "mode": Mode("py"),\n                    "updates": {sharedvar: sharedvar + 1},\n                },\n            )\n\n        assert np.all(pp["y"] == np.arange(5) * 2)\n\n    def test_sample_dims(self, point_list_arg_bug_fixture):\n        pmodel, trace = point_list_arg_bug_fixture\n        with pmodel:\n            post = pm.to_inference_data(trace).posterior.stack(sample=["chain", "draw"])\n            pp = pm.sample_posterior_predictive(post, var_names=["d"], sample_dims=["sample"])\n            assert "sample" in pp.posterior_predictive\n            assert len(pp.posterior_predictive["sample"]) == len(post["sample"])\n            post = post.expand_dims(pred_id=5)\n            pp = pm.sample_posterior_predictive(\n                post, var_names=["d"], sample_dims=["sample", "pred_id"]\n            )\n            assert "sample" in pp.posterior_predictive\n            assert "pred_id" in pp.posterior_predictive\n            assert len(pp.posterior_predictive["sample"]) == len(post["sample"])\n            assert len(pp.posterior_predictive["pred_id"]) == 5\n\n\ndef test_distinct_rvs():\n    """Make sure `RandomVariable`s generated using a `Model`\'s default RNG state all have distinct states."""\n\n    with pm.Model() as model:\n        X_rv = pm.Normal("x")\n        Y_rv = pm.Normal("y")\n\n        pp_samples = pm.sample_prior_predictive(\n            draws=2, return_inferencedata=False, random_seed=npr.default_rng(2023532)\n        )\n\n    assert X_rv.owner.inputs[0] != Y_rv.owner.inputs[0]\n\n    with pm.Model():\n        X_rv = pm.Normal("x")\n        Y_rv = pm.Normal("y")\n\n        pp_samples_2 = pm.sample_prior_predictive(\n            draws=2, return_inferencedata=False, random_seed=npr.default_rng(2023532)\n        )\n\n    assert np.array_equal(pp_samples["y"], pp_samples_2["y"])\n\n\nclass TestNestedRandom:\n    def build_model(self, distribution, shape, nested_rvs_info):\n        with pm.Model() as model:\n            nested_rvs = {}\n            for rv_name, info in nested_rvs_info.items():\n                try:\n                    value, nested_shape = info\n                    loc = 0.0\n                except ValueError:\n                    value, nested_shape, loc = info\n                if value is None:\n                    nested_rvs[rv_name] = pm.Uniform(\n                        rv_name,\n                        0 + loc,\n                        1 + loc,\n                        shape=nested_shape,\n                    )\n                else:\n                    nested_rvs[rv_name] = value * np.ones(nested_shape)\n            rv = distribution(\n                "target",\n                shape=shape,\n                **nested_rvs,\n            )\n        return model, rv, nested_rvs\n\n    def sample_prior(self, distribution, shape, nested_rvs_info, prior_samples):\n        model, rv, nested_rvs = self.build_model(\n            distribution,\n            shape,\n            nested_rvs_info,\n        )\n        with model:\n            return pm.sample_prior_predictive(prior_samples, return_inferencedata=False)\n\n    @pytest.mark.parametrize(\n        ["prior_samples", "shape", "mu", "alpha"],\n        [\n            [10, (3,), (None, ()), (None, (3,))],\n            [10, (3,), (None, (3,)), (None, ())],\n            [\n                10,\n                (\n                    4,\n                    3,\n                ),\n                (None, (3,)),\n                (None, (3,)),\n            ],\n            [\n                10,\n                (\n                    4,\n                    3,\n                ),\n                (None, (3,)),\n                (None, (4, 3)),\n            ],\n        ],\n        ids=str,\n    )\n    def test_NegativeBinomial(\n        self,\n        prior_samples,\n        shape,\n        mu,\n        alpha,\n    ):\n        prior = self.sample_prior(\n            distribution=pm.NegativeBinomial,\n            shape=shape,\n            nested_rvs_info={"mu": mu, "alpha": alpha},\n            prior_samples=prior_samples,\n        )\n        assert prior["target"].shape == (prior_samples, *shape)\n\n    @pytest.mark.parametrize(\n        ["prior_samples", "shape", "psi", "mu", "alpha"],\n        [\n            [10, (3,), (0.5, ()), (None, ()), (None, (3,))],\n            [10, (3,), (0.5, (3,)), (None, ()), (None, (3,))],\n            [10, (3,), (0.5, ()), (None, (3,)), (None, ())],\n            [10, (3,), (0.5, (3,)), (None, (3,)), (None, ())],\n            [\n                10,\n                (\n                    4,\n                    3,\n                ),\n                (0.5, (3,)),\n                (None, (3,)),\n                (None, (3,)),\n            ],\n            [\n                10,\n                (\n                    4,\n                    3,\n                ),\n                (0.5, (3,)),\n                (None, (3,)),\n                (None, (4, 3)),\n            ],\n        ],\n        ids=str,\n    )\n    def test_ZeroInflatedNegativeBinomial(\n        self,\n        prior_samples,\n        shape,\n        psi,\n        mu,\n        alpha,\n    ):\n        prior = self.sample_prior(\n            distribution=pm.ZeroInflatedNegativeBinomial,\n            shape=shape,\n            nested_rvs_info={"psi": psi, "mu": mu, "alpha": alpha},\n            prior_samples=prior_samples,\n        )\n        assert prior["target"].shape == (prior_samples, *shape)\n\n    @pytest.mark.parametrize(\n        ["prior_samples", "shape", "nu", "sigma"],\n        [\n            [10, (3,), (None, ()), (None, (3,))],\n            [10, (3,), (None, ()), (None, (3,))],\n            [10, (3,), (None, (3,)), (None, ())],\n            [10, (3,), (None, (3,)), (None, ())],\n            [\n                10,\n                (\n                    4,\n                    3,\n                ),\n                (None, (3,)),\n                (None, (3,)),\n            ],\n            [\n                10,\n                (\n                    4,\n                    3,\n                ),\n                (None, (3,)),\n                (None, (4, 3)),\n            ],\n        ],\n        ids=str,\n    )\n    def test_Rice(\n        self,\n        prior_samples,\n        shape,\n        nu,\n        sigma,\n    ):\n        prior = self.sample_prior(\n            distribution=pm.Rice,\n            shape=shape,\n            nested_rvs_info={"nu": nu, "sigma": sigma},\n            prior_samples=prior_samples,\n        )\n        assert prior["target"].shape == (prior_samples, *shape)\n\n    @pytest.mark.parametrize(\n        ["prior_samples", "shape", "mu", "sigma", "lower", "upper"],\n        [\n            [10, (3,), (None, ()), (1.0, ()), (None, (), -1), (None, (3,))],\n            [10, (3,), (None, ()), (1.0, ()), (None, (), -1), (None, (3,))],\n            [10, (3,), (None, ()), (1.0, ()), (None, (3,), -1), (None, ())],\n            [10, (3,), (None, ()), (1.0, ()), (None, (3,), -1), (None, ())],\n            [\n                10,\n                (\n                    4,\n                    3,\n                ),\n                (None, (3,)),\n                (1.0, ()),\n                (None, (3,), -1),\n                (None, (3,)),\n            ],\n            [\n                10,\n                (\n                    4,\n                    3,\n                ),\n                (None, (3,)),\n                (1.0, ()),\n                (None, (3,), -1),\n                (None, (4, 3)),\n            ],\n            [10, (3,), (0.0, ()), (None, ()), (None, (), -1), (None, (3,))],\n            [10, (3,), (0.0, ()), (None, ()), (None, (), -1), (None, (3,))],\n            [10, (3,), (0.0, ()), (None, ()), (None, (3,), -1), (None, ())],\n            [10, (3,), (0.0, ()), (None, ()), (None, (3,), -1), (None, ())],\n            [\n                10,\n                (\n                    4,\n                    3,\n                ),\n                (0.0, ()),\n                (None, (3,)),\n                (None, (3,), -1),\n                (None, (3,)),\n            ],\n            [\n                10,\n                (\n                    4,\n                    3,\n                ),\n                (0.0, ()),\n                (None, (3,)),\n                (None, (3,), -1),\n                (None, (4, 3)),\n            ],\n        ],\n        ids=str,\n    )\n    def test_TruncatedNormal(\n        self,\n        prior_samples,\n        shape,\n        mu,\n        sigma,\n        lower,\n        upper,\n    ):\n        prior = self.sample_prior(\n            distribution=pm.TruncatedNormal,\n            shape=shape,\n            nested_rvs_info={"mu": mu, "sigma": sigma, "lower": lower, "upper": upper},\n            prior_samples=prior_samples,\n        )\n        assert prior["target"].shape == (prior_samples, *shape)\n\n    @pytest.mark.parametrize(\n        ["prior_samples", "shape", "c", "lower", "upper"],\n        [\n            [10, (3,), (None, ()), (-1.0, (3,)), (2, ())],\n            [10, (3,), (None, ()), (-1.0, ()), (None, (), 1)],\n            [10, (3,), (None, (3,)), (-1.0, ()), (None, (), 1)],\n            [\n                10,\n                (\n                    4,\n                    3,\n                ),\n                (None, (3,)),\n                (-1.0, ()),\n                (None, (3,), 1),\n            ],\n            [\n                10,\n                (\n                    4,\n                    3,\n                ),\n                (None, (3,)),\n                (None, (), -1),\n                (None, (3,), 1),\n            ],\n        ],\n        ids=str,\n    )\n    def test_Triangular(\n        self,\n        prior_samples,\n        shape,\n        c,\n        lower,\n        upper,\n    ):\n        prior = self.sample_prior(\n            distribution=pm.Triangular,\n            shape=shape,\n            nested_rvs_info={"c": c, "lower": lower, "upper": upper},\n            prior_samples=prior_samples,\n        )\n        assert prior["target"].shape == (prior_samples, *shape)\n\n\ndef test_get_constant_coords():\n    with pm.Model() as model:\n        model.add_coord("length_coord", length=1)\n        model.add_coord("value_coord", values=(3,))\n\n    trace_coords_same = {"length_coord": np.array([0]), "value_coord": np.array([3])}\n    constant_coords_same = get_constant_coords(trace_coords_same, model)\n    assert constant_coords_same == {"length_coord", "value_coord"}\n\n    trace_coords_diff = {"length_coord": np.array([0, 1]), "value_coord": np.array([4])}\n    constant_coords_diff = get_constant_coords(trace_coords_diff, model)\n    assert constant_coords_diff == set()\n\n\ndef test_get_vars_in_point_list():\n    with pm.Model() as modelA:\n        pm.Normal("a", 0, 1)\n        pm.Normal("b", 0, 1)\n        pm.Normal("d", 0, 1)\n    with pm.Model() as modelB:\n        a = pm.Normal("a", 0, 1)\n        pm.Normal("c", 0, 1)\n        pm.Data("d", 0)\n\n    point_list = [{"a": 0, "b": 0, "d": 0}]\n    vars_in_trace = get_vars_in_point_list(point_list, modelB)\n    assert set(vars_in_trace) == {a}\n\n    strace = pm.backends.NDArray(model=modelB, vars=modelA.free_RVs)\n    strace.setup(1, 1)\n    strace.values = point_list[0]\n    strace.draw_idx = 1\n    trace = MultiTrace([strace])\n    vars_in_trace = get_vars_in_point_list(trace, modelB)\n    assert set(vars_in_trace) == {a}\n\n\ndef test_observed_dependent_deterministics():\n    with pm.Model() as m:\n        free = pm.Normal("free")\n        obs = pm.Normal("obs", observed=1)\n\n        det_free = pm.Deterministic("det_free", free + 1)\n        det_free2 = pm.Deterministic("det_free2", det_free + 1)\n\n        det_obs = pm.Deterministic("det_obs", obs + 1)\n        det_obs2 = pm.Deterministic("det_obs2", det_obs + 1)\n\n        det_mixed = pm.Deterministic("det_mixed", free + obs)\n\n    assert set(observed_dependent_deterministics(m)) == {det_obs, det_obs2, det_mixed}\n\n\ndef test_sample_prior_predictive_samples_deprecated_warns() -> None:\n    with pm.Model() as m:\n        pm.Normal("a")\n\n    match = "The samples argument has been deprecated"\n    with pytest.warns(DeprecationWarning, match=match):\n        pm.sample_prior_predictive(model=m, samples=10)\n\n\n@pytest.fixture(params=["deterministic", "observed", "conditioned_on_observed"])\ndef variable_to_vectorize(request):\n    if request.param == "deterministic":\n        return ["y"]\n    elif request.param == "conditioned_on_observed":\n        return ["z", "z_downstream"]\n    else:\n        return ["z"]\n\n\n@pytest.fixture(params=["allow_rvs_in_graph", "disallow_rvs_in_graph"])\ndef allow_rvs_in_graph(request):\n    if request.param == "allow_rvs_in_graph":\n        return True\n    else:\n        return False\n\n\n@pytest.fixture(scope="module", params=["nested_random_variables", "no_nested_random_variables"])\ndef has_nested_random_variables(request):\n    return request.param == "nested_random_variables"\n\n\n@pytest.fixture(scope="module")\ndef model_to_vectorize(has_nested_random_variables):\n    with pm.Model() as model:\n        if not has_nested_random_variables:\n            x_parent = 0.0\n        else:\n            x_parent = pm.Normal("x_parent")\n        x = pm.Normal("x", mu=x_parent)\n        d = pm.Data("d", np.array([1, 2, 3]))\n        obs = pm.Data("obs", np.ones_like(d.get_value()))\n        y = pm.Deterministic("y", x * d)\n        z = pm.Gamma("z", mu=pt.exp(y), sigma=pt.exp(y) * 0.1, observed=obs)\n        pm.Deterministic("z_downstream", z * 2)\n\n    with model:\n        idata = pm.sample_prior_predictive(100)\n        idata.add_groups({"posterior": idata.prior})\n    return freeze_dims_and_data(model), idata\n\n\n@pytest.fixture(params=["rv_from_posterior", "resample_rv"])\ndef input_rv_names(request, has_nested_random_variables):\n    if request.param == "rv_from_posterior":\n        if has_nested_random_variables:\n            return ["x_parent", "x"]\n        else:\n            return ["x"]\n    else:\n        return []\n\n\ndef test_vectorize_over_posterior(\n    variable_to_vectorize,\n    input_rv_names,\n    allow_rvs_in_graph,\n    model_to_vectorize,\n):\n    model, idata = model_to_vectorize\n\n    if not allow_rvs_in_graph and (len(input_rv_names) == 0 or "z" in variable_to_vectorize):\n        with pytest.raises(\n            RuntimeError,\n            match="The following random variables found in the extracted graph",\n        ):\n            vectorize_over_posterior(\n                outputs=[model[name] for name in variable_to_vectorize],\n                posterior=idata.posterior,\n                input_rvs=[model[name] for name in input_rv_names],\n                allow_rvs_in_graph=allow_rvs_in_graph,\n            )\n    else:\n        vectorized = vectorize_over_posterior(\n            outputs=[model[name] for name in variable_to_vectorize],\n            posterior=idata.posterior,\n            input_rvs=[model[name] for name in input_rv_names],\n            allow_rvs_in_graph=allow_rvs_in_graph,\n        )\n        assert all(\n            vectorized_var is not model[name]\n            for vectorized_var, name in zip(vectorized, variable_to_vectorize)\n        )\n        assert all(vectorized_var.type.shape == (1, 100, 3) for vectorized_var in vectorized)\n        assert all(variable_depends_on(vectorized_var, model["d"]) for vectorized_var in vectorized)\n        if len(vectorized) == 2:\n            assert variable_depends_on(\n                vectorized[variable_to_vectorize.index("z_downstream")],\n                vectorized[variable_to_vectorize.index("z")],\n            )\n        if len(input_rv_names) > 0:\n            for input_rv_name in input_rv_names:\n                if input_rv_name == "x_parent":\n                    assert len(get_var_by_name(vectorized, input_rv_name)) == 0\n                else:\n                    [vectorized_rv] = get_var_by_name(vectorized, input_rv_name)\n                    rv_posterior = idata.posterior[input_rv_name].data\n                    assert isinstance(vectorized_rv, TensorConstant)\n                    assert np.all(vectorized_rv.value == rv_posterior)\n        else:\n            batch_shape = (\n                len(idata.posterior.coords["chain"]),\n                len(idata.posterior.coords["draw"]),\n            )\n            original_rvs = rvs_in_graph([model[name] for name in variable_to_vectorize])\n            expected_rv_shapes = {(*batch_shape, *rv.type.shape) for rv in original_rvs}\n            rvs = rvs_in_graph(vectorized)\n            assert {rv.type.shape for rv in rvs} == expected_rv_shapes\n\n\ndef test_vectorize_over_posterior_matches_sample():\n    rng = np.random.default_rng(1234)\n    with pm.Model() as model:\n        x = pm.Normal("x")\n        sigma = 0.1\n        obs = pm.Normal("obs", x, sigma, observed=rng.normal(size=10))\n        det = pm.Deterministic("det", obs + 1)\n\n    chains = 2\n    draws = 100\n    x_posterior = np.broadcast_to(100 * np.arange(chains)[..., None], (chains, draws))\n    with model:\n        posterior = xr.Dataset(\n            {\n                "x": xr.DataArray(\n                    x_posterior,\n                    dims=("chain", "draw"),\n                    coords={"chain": np.arange(chains), "draw": np.arange(draws)},\n                )\n            }\n        )\n    idata = InferenceData(posterior=posterior)\n    with model:\n        pp = pm.sample_posterior_predictive(idata, var_names=["obs", "det"], random_seed=1234)\n        vectorized = vectorize_over_posterior(\n            outputs=[obs, det],\n            posterior=posterior,\n            input_rvs=[x],\n            allow_rvs_in_graph=True,\n        )\n        [vect_obs, vect_det] = compile(inputs=[], outputs=vectorized, random_seed=1234)()\n        assert pp.posterior_predictive["obs"].shape == vect_obs.shape\n        assert pp.posterior_predictive["det"].shape == vect_det.shape\n        np.testing.assert_allclose(vect_obs + 1, vect_det)\n        np.testing.assert_allclose(\n            pp.posterior_predictive["obs"].mean(dim=("chain", "draw")),\n            vect_obs.mean(axis=(0, 1)),\n            atol=0.6 / np.sqrt(10000),\n        )\n        assert np.all(np.abs(vect_obs - x_posterior[..., None]) < 1)\n',
        }
